import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MessageRole {
  USER = 'user',
  MODEL = 'model',
  SYSTEM = 'system'
}

export interface Message {
  id: string;
  role: MessageRole;
  content: string;
  timestamp: number;
  image?: string;
}

export interface TelegramUser {
  id: number;
  first_name: string;
  last_name?: string;
  username?: string;
  language_code?: string;
  photo_url?: string;
}

export enum AppTab {
  CHAT = 'chat',
  ANALYTICS = 'analytics',
  SETTINGS = 'settings'
}

import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Message, MessageRole } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;
  private modelName = 'gemini-3-flash-preview';

  constructor() {
    // API_KEY is provided by the environment
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateSimpleResponse(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: this.modelName,
        contents: prompt,
      });
      return response.text || "I'm sorry, I couldn't generate a response.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "An error occurred while communicating with the AI.";
    }
  }

  async *streamResponse(history: Message[]): AsyncGenerator<string> {
    try {
      const chat: Chat = this.ai.chats.create({
        model: this.modelName,
        config: {
          systemInstruction: "You are a helpful AI assistant inside a Telegram Mini App. Keep your responses concise and friendly. Use Telegram markdown where appropriate.",
        },
      });

      // We only send the last user message to the stream for simplicity in this demo,
      // but a real app would reconstruct the history.
      const lastMessage = history[history.length - 1];

      const responseStream = await chat.sendMessageStream({ message: lastMessage.content });

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          yield c.text;
        }
      }
    } catch (error) {
      console.error("Gemini Streaming Error:", error);
      yield "Error: Failed to get response from AI.";
    }
  }

  async analyzeImage(prompt: string, base64Image: string): Promise<string> {
    try {
      const imagePart = {
        inlineData: {
          mimeType: 'image/jpeg',
          data: base64Image.split(',')[1] || base64Image,
        },
      };
      const textPart = { text: prompt };

      const response = await this.ai.models.generateContent({
        model: this.modelName,
        contents: { parts: [imagePart, textPart] },
      });

      return response.text || "I couldn't analyze the image.";
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return "Failed to analyze image.";
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageRole, TelegramUser, AppTab } from './types';
import { geminiService } from './services/geminiService';
import { 
  ChatBubbleLeftRightIcon, 
  ChartBarIcon, 
  Cog6ToothIcon,
  PaperAirplaneIcon,
  PhotoIcon,
  UserCircleIcon
} from '@heroicons/react/24/outline';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.CHAT);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: MessageRole.MODEL,
      content: 'Hello! I am Gemini, your personal AI assistant. How can I help you today?',
      timestamp: Date.now()
    }
