    // Initialize Telegram Web App
    if (window.Telegram && window.Telegram.WebApp) {
      const tg = window.Telegram.WebApp;
      tg.expand();
      tg.ready();

      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user as TelegramUser);
      }
    }
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSendMessage = async () => {
    if ((!input.trim() && !selectedImage) || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      content: input,
      timestamp: Date.now(),
      image: selectedImage || undefined
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      let responseText = '';
      if (selectedImage) {
        responseText = await geminiService.analyzeImage(input || "What is in this image?", selectedImage);
        setSelectedImage(null);
      } else {
        // Stream the response for better UX
        const assistantMsgId = (Date.now() + 1).toString();
        const assistantMsg: Message = {
          id: assistantMsgId,
          role: MessageRole.MODEL,
          content: '',
          timestamp: Date.now()
        };

        setMessages(prev => [...prev, assistantMsg]);

        let fullContent = '';
        for await (const chunk of geminiService.streamResponse([...messages, userMsg])) {
          fullContent += chunk;
          setMessages(prev => prev.map(m => m.id === assistantMsgId ? { ...m, content: fullContent } : m));
        }
        setIsLoading(false);
        return;
      }

      const assistantMsg: Message = {
        id: Date.now().toString(),
        role: MessageRole.MODEL,
        content: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMsg]);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const analyticsData = [
    { name: 'Mon', count: 12 },
    { name: 'Tue', count: 19 },
    { name: 'Wed', count: 3 },
    { name: 'Thu', count: 5 },
    { name: 'Fri', count: 2 },
    { name: 'Sat', count: 3 },
    { name: 'Sun', count: 8 },
  ];

  return (
    <div className="flex flex-col h-screen overflow-hidden text-[var(--tg-theme-text-color)]">
      {/* Header */}
      <header className="px-4 py-3 flex items-center justify-between border-b border-[var(--tg-theme-secondary-bg-color)] bg-[var(--tg-theme-bg-color)] sticky top-0 z-10">
        <div className="flex items-center gap-2">
          {user?.photo_url ? (
            <img src={user.photo_url} className="w-8 h-8 rounded-full" alt="User" />
          ) : (
            <UserCircleIcon className="w-8 h-8 text-[var(--tg-theme-hint-color, #999)]" />
          )}
          <span className="font-semibold text-lg">{user?.first_name || 'Guest'}</span>
        </div>
        <div className="text-xs text-[var(--tg-theme-hint-color, #999)] bg-[var(--tg-theme-secondary-bg-color)] px-2 py-1 rounded-full">
          Gemini 3 Flash
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto hide-scrollbar bg-[var(--tg-theme-secondary-bg-color)]">
        {activeTab === AppTab.CHAT && (
          <div ref={scrollRef} className="p-4 space-y-4 flex flex-col min-h-full">
            {messages.map((msg) => (
              <div 
                key={msg.id} 
                className={`flex ${msg.role === MessageRole.USER ? 'justify-end' : 'justify-start'}`}
              >
                <div className={`max-w-[85%] rounded-2xl px-4 py-2 shadow-sm ${
                  msg.role === MessageRole.USER 
                    ? 'bg-[var(--tg-theme-button-color, #2481cc)] text-[var(--tg-theme-button-text-color, #ffffff)] rounded-tr-none' 
                    : 'bg-[var(--tg-theme-bg-color, #ffffff)] text-[var(--tg-theme-text-color, #222222)] rounded-tl-none border border-gray-100'
                }`}>
                  {msg.image && (
