                  )}
                  <p className="text-sm whitespace-pre-wrap leading-relaxed">{msg.content}</p>
                  <p className={`text-[10px] mt-1 text-right opacity-60`}>
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-[var(--tg-theme-bg-color)] p-3 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-1">
                  <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === AppTab.ANALYTICS && (
          <div className="p-6 space-y-6">
            <h2 className="text-xl font-bold">Usage Analytics</h2>
            <div className="bg-[var(--tg-theme-bg-color)] p-4 rounded-xl shadow-sm h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={analyticsData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} />
                  <YAxis fontSize={12} tickLine={false} axisLine={false} />
                  <Tooltip 
                    cursor={{fill: 'transparent'}}
                    contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                  />
                  <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                    {analyticsData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index === 1 ? 'var(--tg-theme-button-color, #2481cc)' : '#cbd5e1'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-[var(--tg-theme-bg-color)] p-4 rounded-xl shadow-sm text-center">
                <p className="text-[var(--tg-theme-hint-color)] text-xs uppercase font-semibold">Total Queries</p>
                <p className="text-2xl font-bold mt-1">52</p>
              </div>
              <div className="bg-[var(--tg-theme-bg-color)] p-4 rounded-xl shadow-sm text-center">
                <p className="text-[var(--tg-theme-hint-color)] text-xs uppercase font-semibold">Avg. Accuracy</p>
                <p className="text-2xl font-bold mt-1 text-green-500">98%</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === AppTab.SETTINGS && (
          <div className="p-4 space-y-4">
            <h2 className="text-xl font-bold mb-4">Settings</h2>
            <div className="bg-[var(--tg-theme-bg-color)] rounded-xl overflow-hidden shadow-sm">
              <div className="p-4 flex items-center justify-between border-b border-gray-50">
                <span>Model Version</span>
                <span className="text-sm text-[var(--tg-theme-hint-color)]">3.0 Flash Preview</span>
              </div>
              <div className="p-4 flex items-center justify-between border-b border-gray-50">
                <span>Language</span>
                <span className="text-sm text-[var(--tg-theme-hint-color)]">English</span>
              </div>
              <div className="p-4 flex items-center justify-between">
                <span>Enable Voice Responses</span>
                <div className="w-10 h-6 bg-blue-500 rounded-full p-1 cursor-pointer">
                  <div className="w-4 h-4 bg-white rounded-full ml-auto"></div>
                </div>
              </div>
            </div>

            <div className="bg-[var(--tg-theme-bg-color)] rounded-xl p-4 shadow-sm mt-4">
              <p className="text-sm text-[var(--tg-theme-hint-color)] text-center">
                Built with ❤️ using Gemini API & Telegram SDK
              </p>
            </div>
          </div>
        )}
      </main>

      {/* Input Bar (Only on Chat Tab) */}
      {activeTab === AppTab.CHAT && (
        <div className="p-3 bg-[var(--tg-theme-bg-color)] border-t border-[var(--tg-theme-secondary-bg-color)]">
          {selectedImage && (
            <div className="mb-2 relative inline-block">
              <img src={selectedImage} className="w-16 h-16 rounded-md object-cover border" alt="Preview" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-xs"
              >
                ×
              </button>
            </div>
          )}
          <div className="flex items-center gap-2">
            <label className="p-2 text-[var(--tg-theme-button-color, #2481cc)] cursor-pointer active:opacity-60 transition-opacity">
              <PhotoIcon className="w-6 h-6" />
              <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
            </label>
            <textarea 
              rows={1}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSendMessage();
                }
              }}
              placeholder="Type a message..."
              className="flex-1 bg-[var(--tg-theme-secondary-bg-color)] text-[var(--tg-theme-text-color)] rounded-2xl px-4 py-2 focus:outline-none resize-none max-h-32 text-sm"
            />
            <button 
              onClick={handleSendMessage}
              disabled={isLoading || (!input.trim() && !selectedImage)}
              className="p-2 bg-[var(--tg-theme-button-color, #2481cc)] text-[var(--tg-theme-button-text-color, #ffffff)] rounded-full disabled:opacity-50 active:scale-95 transition-transform"
            >
              <PaperAirplaneIcon className="w-5 h-5 -rotate-45" />
            </button>
          </div>
        </div>
      )}

      {/* Bottom Navigation */}
      <nav className="flex items-center justify-around py-2 border-t border-[var(--tg-theme-secondary-bg-color)] bg-[var(--tg-theme-bg-color)] mb-safe">
        <button 
          onClick={() => setActiveTab(AppTab.CHAT)}
          className={`flex flex-col items-center gap-1 w-full transition-colors ${activeTab === AppTab.CHAT ? 'text-[var(--tg-theme-button-color, #2481cc)]' : 'text-[var(--tg-theme-hint-color, #999)]'}`}
        >
          <ChatBubbleLeftRightIcon className="w-6 h-6" />
          <span className="text-[10px] font-medium">Chat</span>
        </button>
        <button 
          onClick={() => setActiveTab(AppTab.ANALYTICS)}
          className={`flex flex-col items-center gap-1 w-full transition-colors ${activeTab === AppTab.ANALYTICS ? 'text-[var(--tg-theme-button-color, #2481cc)]' : 'text-[var(--tg-theme-hint-color, #999)]'}`}
        >
          <ChartBarIcon className="w-6 h-6" />
          <span className="text-[10px] font-medium">Data</span>
        </button>
        <button 
          onClick={() => setActiveTab(AppTab.SETTINGS)}
          className={`flex flex-col items-center gap-1 w-full transition-colors ${activeTab === AppTab.SETTINGS ? 'text-[var(--tg-theme-button-color, #2481cc)]' : 'text-[var(--tg-theme-hint-color, #999)]'}`}
        >
          <Cog6ToothIcon className="w-6 h-6" />
          <span className="text-[10px] font-medium">Settings</span>
        </button>
      </nav>
    </div>
  );
};

