import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Message, MessageRole } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;
  private modelName = 'gemini-3-flash-preview';

  constructor() {
    // Fix: Initializing GoogleGenAI using the required named parameter object and directly using process.env.API_KEY.
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
  }

  async generateSimpleResponse(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: this.modelName,
        contents: prompt,
      });
      // Fix: Accessing .text as a property rather than calling it as a method.
      return response.text || "I'm sorry, I couldn't generate a response.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "An error occurred while communicating with the AI.";
    }
  }

  async *streamResponse(history: Message[]): AsyncGenerator<string> {
    try {
      const chat: Chat = this.ai.chats.create({
        model: this.modelName,
        config: {
          systemInstruction: "You are a helpful AI assistant inside a Telegram Mini App. Keep your responses concise and friendly. Use Telegram markdown where appropriate.",
        },
      });

      // We only send the last user message to the stream for simplicity in this demo,
      // but a real app would reconstruct the history.
      const lastMessage = history[history.length - 1];

      const responseStream = await chat.sendMessageStream({ message: lastMessage.content });

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        // Fix: Accessing .text as a property on the chunk from the stream.
        if (c.text) {
          yield c.text;
        }
      }
    } catch (error) {
      console.error("Gemini Streaming Error:", error);
      yield "Error: Failed to get response from AI.";
    }
  }

  async analyzeImage(prompt: string, base64Image: string): Promise<string> {
    try {
      const imagePart = {
        inlineData: {
          mimeType: 'image/jpeg',
          data: base64Image.split(',')[1] || base64Image,
        },
      };
      const textPart = { text: prompt };

      const response = await this.ai.models.generateContent({
        model: this.modelName,
        contents: { parts: [imagePart, textPart] },
      });

      // Fix: Accessing .text as a property for image analysis response.
      return response.text || "I couldn't analyze the image.";
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return "Failed to analyze image.";
    }
  }
}

