          </button>
          <button 
            onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }}
            className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${payoutType === 'trc20' ? 'bg-white shadow-sm' : 'opacity-50'}`}
          >
            TRC20 (USDT)
          </button>
        </div>

        <div className="space-y-4">
          <div className="relative">
            <div className="absolute left-4 top-1/2 -translate-y-1/2">
              {payoutType === 'card' ? <CreditCardIcon className="w-6 h-6 text-gray-400" /> : <CurrencyDollarIcon className="w-6 h-6 text-green-500" />}
            </div>
            <input 
              type="text"
              placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька TRC20"}
              value={payoutValue}
              onChange={(e) => setPayoutValue(e.target.value)}
              maxLength={payoutType === 'card' ? 19 : 42}
              className="w-full py-4 pl-12 pr-4 bg-[var(--tg-theme-secondary-bg-color)] rounded-2xl font-mono text-lg"
            />
          </div>
          <p className="text-[10px] text-[var(--tg-theme-hint-color)] px-2 uppercase tracking-wider font-bold">
            {payoutType === 'card' ? "Введите 16 цифр карты" : "Введите адрес, начинающийся на T"}
          </p>
        </div>
      </div>

      <button
        disabled={!validatePayout()}
        onClick={() => setStep(ContestStep.FINAL)}
        className="w-full py-4 rounded-2xl font-bold text-lg btn-primary disabled:opacity-30 disabled:grayscale transition-all"
      >
        Продолжить
      </button>
    </div>
  );

  const renderFinalStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center">
      <div className="flex-1 flex flex-col justify-center space-y-6">
        <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mx-auto">
          <CheckBadgeIcon className="w-14 h-14 text-green-500" />
        </div>
        <div className="space-y-2">
          <h1 className="text-3xl font-black">Почти готово!</h1>
          <p className="text-[var(--tg-theme-hint-color)]">
            Вы подтвердили реферала и указали реквизиты: <br/>
            <span className="text-[var(--tg-theme-text-color)] font-mono break-all">{payoutValue}</span>
          </p>
        </div>
      </div>

      <button
        disabled={isFinalizing}
        onClick={handleFinalParticipate}
        className="w-full py-4 rounded-2xl font-bold text-xl btn-primary shadow-lg shadow-blue-500/30 flex items-center justify-center gap-2"
      >
        {isFinalizing ? <ClockIcon className="w-6 h-6 animate-spin" /> : 'УЧАСТВОВАТЬ'}
      </button>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center justify-center space-y-8">
      <div className="relative">
        <div className="absolute inset-0 bg-green-400 blur-3xl opacity-20 rounded-full animate-pulse"></div>
        <div className="relative w-32 h-32 bg-green-500 rounded-full flex items-center justify-center mx-auto text-white shadow-2xl">
          <CheckBadgeIcon className="w-20 h-20" />
        </div>
      </div>
      <div className="space-y-4">
        <h1 className="text-3xl font-bold">Вы в деле!</h1>
        <p className="text-[var(--tg-theme-hint-color)] px-4 text-lg">
          Ваша заявка принята. Ожидайте результатов конкурса в официальном канале.
        </p>
      </div>
      <button 
        onClick={() => window.Telegram?.WebApp?.close()}
        className="mt-8 font-bold text-blue-500 hover:opacity-70 transition-opacity"
      >
        Закрыть приложение
      </button>
    </div>
  );

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] select-none overflow-hidden">
      {step === ContestStep.REFERRAL && renderReferralStep()}
      {step === ContestStep.PAYOUT && renderPayoutStep()}
      {step === ContestStep.FINAL && renderFinalStep()}
      {step === ContestStep.SUCCESS && renderSuccess()}

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-fade-in { animation: fade-in 0.4s ease-out forwards; }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

export default App;

export interface TelegramUser {
  id: number;
  first_name: string;
  last_name?: string;
  username?: string;
  photo_url?: string;
}

export interface Contest {
  id: string;
  title: string;
  description: string;
  referralLink: string;
  createdAt: number;
}

export enum ContestStep {
  LIST = 'list',
  REFERRAL = 'referral',
  PAYOUT = 'payout',
  FINAL = 'final',
  SUCCESS = 'success'
}

export type PayoutType = 'card' | 'trc20';

declare global {
  interface Window {
    Telegram?: {
      WebApp: {
        ready: () => void;
        expand: () => void;
        close: () => void;
        initDataUnsafe: {
          user?: TelegramUser;
        };
        HapticFeedback: {
          impactOccurred: (style: 'light' | 'medium' | 'heavy' | 'rigid' | 'soft') => void;
        };
      };
    };
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon
} from '@heroicons/react/24/outline';

const ADMIN_ID = 7946967720;
const STORAGE_KEY = 'beef_contests_v1';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);

  // Participation Flow State
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin Form State
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }

    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setContests(JSON.parse(saved));
    } else {
      // Default initial contest
      const initial = [{
        id: 'default',
        title: 'Первый розыгрыш Beef',
        description: 'Участвуй и выиграй ценные призы!',
        referralLink: 'https://beef-way-one.com/c22082169',
        createdAt: Date.now()
      }];
      setContests(initial);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(initial));
    }
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const saveContests = (newContests: Contest[]) => {
    setContests(newContests);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newContests));
  };

  const createContest = () => {
    if (!newTitle || !newLink) return;
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      referralLink: newLink,
      createdAt: Date.now()
    };
    saveContests([contest, ...contests]);
    setNewTitle('');
    setNewDesc('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = (id: string) => {
    saveContests(contests.filter(c => c.id !== id));
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
  };

  const startParticipation = (contest: Contest) => {
    setSelectedContest(contest);
    setStep(ContestStep.REFERRAL);
    setCheckAttempts(0);
    setError(null);
  };

  const handleReferralCheck = () => {
    setIsChecking(true);
    setError(null);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    // 3 seconds cooldown as requested
    setTimeout(() => {
      setIsChecking(false);
      if (checkAttempts < 2) {
        setCheckAttempts(prev => prev + 1);
        setError("Проверь, зарегистрировался ли ты на Beef, или повтори попытку");
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('heavy');
      } else {
        setStep(ContestStep.PAYOUT);
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('soft');
      }
    }, 3000);
  };

  const validatePayout = () => {
    if (payoutType === 'card') {
      return /^\d{16}$/.test(payoutValue.replace(/\s/g, ''));
    }
    return /^T[a-zA-Z0-9]{33}$/.test(payoutValue.trim());
  };

  const handleFinalParticipate = () => {
    setIsFinalizing(true);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
    setTimeout(() => {
      setIsFinalizing(false);
      setStep(ContestStep.SUCCESS);
      window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
    }, 1500);
  };

  const renderAdminPanel = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-2xl font-black flex items-center gap-2">
          <ShieldCheckIcon className="w-8 h-8 text-orange-500" />
          Админ-панель
        </h1>
        <button onClick={() => setView('user')} className="text-blue-500 font-bold">Выйти</button>
      </div>

      <div className="bg-[var(--tg-theme-secondary-bg-color)] p-5 rounded-3xl space-y-4 mb-8 border border-gray-100 dark:border-gray-800 shadow-sm">
        <h2 className="text-lg font-bold flex items-center gap-2">
          <PlusIcon className="w-5 h-5" /> Новый розыгрыш
        </h2>
        <input 
          placeholder="Название розыгрыша" 
          value={newTitle} 
          onChange={e => setNewTitle(e.target.value)}
          className="w-full p-3 bg-white dark:bg-black rounded-xl border border-gray-200"
        />
        <textarea 
          placeholder="Описание" 
          value={newDesc} 
          onChange={e => setNewDesc(e.target.value)}
          className="w-full p-3 bg-white dark:bg-black rounded-xl border border-gray-200 h-20"
        />
        <input 
          placeholder="Реферальная ссылка" 
          value={newLink} 
          onChange={e => setNewLink(e.target.value)}
          className="w-full p-3 bg-white dark:bg-black rounded-xl border border-gray-200"
        />
        <button 
          onClick={createContest}
          disabled={!newTitle || !newLink}
          className="w-full py-3 bg-orange-500 text-white rounded-xl font-bold active:scale-95 transition-transform disabled:opacity-50"
        >
          Создать розыгрыш
        </button>
      </div>

      <div className="space-y-4">
        <h2 className="text-lg font-bold">Список розыгрышей</h2>
        {contests.map(c => (
          <div key={c.id} className="p-4 bg-[var(--tg-theme-secondary-bg-color)] rounded-2xl flex justify-between items-center shadow-sm">
            <div>
              <p className="font-bold">{c.title}</p>
              <p className="text-xs text-[var(--tg-theme-hint-color)]">Создан: {new Date(c.createdAt).toLocaleDateString()}</p>
            </div>
            <button onClick={() => deleteContest(c.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-full transition-colors">
              <TrashIcon className="w-5 h-5" />
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  const renderContestList = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-10">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-blue-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
            <TrophyIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-xl font-black">Розыгрыши</h1>
            <p className="text-xs text-[var(--tg-theme-hint-color)]">Активные события</p>
          </div>
        </div>
        {isAdmin && (
          <button 
            onClick={() => setView('admin')}
            className="p-3 bg-gray-100 dark:bg-gray-800 rounded-full active:scale-90 transition-transform"
          >
            <ShieldCheckIcon className="w-6 h-6 text-blue-500" />
          </button>
        )}
      </div>

      <div className="space-y-4">
        {contests.length === 0 ? (
          <div className="text-center py-20 text-[var(--tg-theme-hint-color)]">
            <UserGroupIcon className="w-16 h-16 mx-auto mb-4 opacity-20" />
            <p>Нет активных розыгрышей</p>
          </div>
        ) : (
          contests.map(c => (
            <div 
              key={c.id} 
              onClick={() => startParticipation(c)}
              className="p-5 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl border border-gray-100 dark:border-gray-800 shadow-sm active:scale-[0.98] transition-all relative overflow-hidden group"
            >
              <div className="absolute top-0 right-0 w-24 h-24 bg-blue-500/5 -mr-8 -mt-8 rounded-full"></div>
              <h3 className="text-lg font-black mb-1">{c.title}</h3>
              <p className="text-sm text-[var(--tg-theme-hint-color)] mb-4 line-clamp-2">{c.description}</p>
              <div className="flex items-center justify-between">
                <span className="text-[10px] uppercase tracking-wider font-black text-blue-500 flex items-center gap-1">
                  Участвовать <ArrowRightIcon className="w-3 h-3" />
                </span>
                <div className="flex -space-x-2">
                  <div className="w-6 h-6 bg-blue-100 rounded-full border-2 border-[var(--tg-theme-secondary-bg-color)]"></div>
                  <div className="w-6 h-6 bg-blue-200 rounded-full border-2 border-[var(--tg-theme-secondary-bg-color)]"></div>
                  <div className="w-6 h-6 bg-blue-300 rounded-full border-2 border-[var(--tg-theme-secondary-bg-color)]"></div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );

  const renderReferralStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <button onClick={() => setStep(ContestStep.LIST)} className="mb-4 flex items-center gap-1 text-blue-500 font-bold">
        <ChevronLeftIcon className="w-5 h-5" /> Назад
      </button>
      <div className="flex-1 flex flex-col justify-center items-center text-center space-y-8">
        <div className="w-24 h-24 bg-blue-100 dark:bg-blue-900/30 rounded-[2.5rem] flex items-center justify-center shadow-inner">
          <LinkIcon className="w-12 h-12 text-blue-500" />
        </div>
        <div className="space-y-3">
          <h1 className="text-3xl font-black">{selectedContest?.title}</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg px-6 leading-tight">
            Стань рефералом <span className="text-blue-500 font-bold">Beef</span> для участия.
          </p>
        </div>

        <a 
          href={selectedContest?.referralLink} 
          target="_blank"
          className="w-full p-5 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl flex items-center justify-between border-2 border-blue-500 shadow-xl shadow-blue-500/10 active:scale-[0.98] transition-transform"
        >
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-500 rounded-xl flex items-center justify-center text-white">
              <LinkIcon className="w-6 h-6" />
            </div>
            <span className="font-black text-blue-500">РЕГИСТРАЦИЯ BEEF</span>
          </div>
          <ArrowRightIcon className="w-5 h-5 text-blue-500" />
        </a>

        {error && (
          <div className="flex items-center gap-3 p-4 bg-red-50 dark:bg-red-900/10 text-red-600 rounded-2xl text-sm animate-shake border border-red-100 dark:border-red-900/20">
            <ExclamationCircleIcon className="w-6 h-6 flex-shrink-0" />
            <p className="text-left leading-tight font-bold">{error}</p>
          </div>
        )}
      </div>

      <button
        disabled={isChecking}
        onClick={handleReferralCheck}
        className="w-full py-5 rounded-3xl font-black text-xl btn-primary flex items-center justify-center gap-3 disabled:opacity-50 transition-all shadow-xl shadow-blue-500/20 active:scale-95"
      >
        {isChecking ? (
          <>
            <ClockIcon className="w-6 h-6 animate-spin" />
            ПРОВЕРКА...
          </>
        ) : (
          'ПРОВЕРИТЬ'
        )}
      </button>
    </div>
  );

  const renderPayoutStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <div className="flex-1 space-y-8 pt-8">
        <div className="space-y-3">
          <h1 className="text-3xl font-black">Реквизиты</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-tight">
            Куда отправить твой выигрыш в случае удачи?
          </p>
        </div>

        <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-inner">
          <button 
            onClick={() => { setPayoutType('card'); setPayoutValue(''); }}
            className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${payoutType === 'card' ? 'bg-white dark:bg-black shadow-lg shadow-gray-200/50 dark:shadow-none' : 'opacity-40'}`}
          >
            КАРТА
          </button>
          <button 
            onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }}
            className={`flex-1 py-3 rounded-xl text-sm font-black transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-black shadow-lg shadow-gray-200/50 dark:shadow-none' : 'opacity-40'}`}
          >
            TRC20
          </button>
        </div>

        <div className="space-y-4">
          <div className="relative group">
            <div className="absolute left-5 top-1/2 -translate-y-1/2 transition-colors group-focus-within:text-blue-500">
              {payoutType === 'card' ? <CreditCardIcon className="w-7 h-7 text-gray-400" /> : <CurrencyDollarIcon className="w-7 h-7 text-green-500" />}
            </div>
            <input 
              type="text"
              placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька TRC20"}
              value={payoutValue}
              onChange={(e) => setPayoutValue(e.target.value)}
              maxLength={payoutType === 'card' ? 19 : 42}
              className="w-full py-5 pl-14 pr-5 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl font-mono text-xl border-2 border-transparent focus:border-blue-500 transition-all outline-none"
            />
          </div>
          <div className="px-5">
            <p className="text-[10px] text-blue-500 uppercase tracking-[0.2em] font-black opacity-60">
              {payoutType === 'card' ? "Введите 16 цифр вашей карты" : "Введите корректный адрес сети Tron"}
            </p>
          </div>
        </div>
      </div>

      <button
        disabled={!validatePayout()}
        onClick={() => setStep(ContestStep.FINAL)}
        className="w-full py-5 rounded-3xl font-black text-xl btn-primary disabled:opacity-20 disabled:grayscale transition-all shadow-xl shadow-blue-500/20 active:scale-95"
      >
        ПРОДОЛЖИТЬ
      </button>
    </div>
  );

  const renderFinalStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center">
      <div className="flex-1 flex flex-col justify-center space-y-8">
        <div className="relative w-32 h-32 mx-auto">
          <div className="absolute inset-0 bg-blue-500/20 rounded-[2.5rem] blur-2xl animate-pulse"></div>
          <div className="relative w-full h-full bg-blue-100 dark:bg-blue-900/30 rounded-[2.5rem] flex items-center justify-center border-2 border-blue-500/20 shadow-inner">
            <CheckBadgeIcon className="w-16 h-16 text-blue-500" />
          </div>
        </div>
        <div className="space-y-3">
          <h1 className="text-4xl font-black tracking-tight">ФИНАЛ!</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-tight px-10">
            Все условия выполнены. Жми кнопку ниже для участия в <br/>
            <span className="text-[var(--tg-theme-text-color)] font-black italic">{selectedContest?.title}</span>
          </p>
        </div>
        <div className="p-4 bg-[var(--tg-theme-secondary-bg-color)] rounded-2xl mx-6 border border-gray-100 dark:border-gray-800">
          <p className="text-[10px] text-[var(--tg-theme-hint-color)] uppercase tracking-widest font-black mb-1">Твои реквизиты:</p>
          <p className="font-mono text-sm break-all font-bold">{payoutValue}</p>
        </div>
      </div>

      <button
        disabled={isFinalizing}
        onClick={handleFinalParticipate}
        className="w-full py-6 rounded-[2rem] font-black text-2xl btn-primary shadow-2xl shadow-blue-500/40 flex items-center justify-center gap-3 active:scale-95 transition-all"
      >
        {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin" /> : 'УЧАСТВОВАТЬ'}
      </button>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center justify-center space-y-10">
      <div className="relative">
        <div className="absolute inset-0 bg-green-400 blur-[4rem] opacity-30 rounded-full animate-pulse"></div>
        <div className="relative w-40 h-40 bg-gradient-to-tr from-green-500 to-emerald-400 rounded-full flex items-center justify-center mx-auto text-white shadow-3xl">
          <CheckBadgeIcon className="w-24 h-24 drop-shadow-lg" />
        </div>
      </div>
      <div className="space-y-4">
        <h1 className="text-4xl font-black tracking-tight">ТЫ В ДЕЛЕ!</h1>
        <p className="text-[var(--tg-theme-hint-color)] px-8 text-xl leading-snug">
          Твоя заявка успешно зарегистрирована. Желаем удачи в розыгрыше!
        </p>
      </div>
      <button 
        onClick={() => setStep(ContestStep.LIST)}
        className="mt-8 font-black text-blue-500 text-lg hover:opacity-70 transition-opacity flex items-center justify-center gap-2 mx-auto"
      >
        <ChevronLeftIcon className="w-6 h-6" /> Вернуться к списку
      </button>
    </div>
  );

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] select-none overflow-hidden text-[var(--tg-theme-text-color)]">
      {view === 'admin' ? renderAdminPanel() : (
        <>
          {step === ContestStep.LIST && renderContestList()}
          {step === ContestStep.REFERRAL && renderReferralStep()}
          {step === ContestStep.PAYOUT && renderPayoutStep()}
          {step === ContestStep.FINAL && renderFinalStep()}
          {step === ContestStep.SUCCESS && renderSuccess()}
        </>
      )}

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: scale(0.95) translateY(10px); }
          to { opacity: 1; transform: scale(1) translateY(0); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-6px); }
          75% { transform: translateX(6px); }
        }
        .animate-fade-in { animation: fade-in 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-shake { animation: shake 0.15s ease-in-out 0s 2; }

        .shadow-3xl {
          box-shadow: 0 20px 50px -10px rgba(16, 185, 129, 0.4);
        }
      `}</style>
    </div>
  );
};

export default App;

export interface TelegramUser {
  id: number;
  first_name: string;
  last_name?: string;
  username?: string;
  photo_url?: string;
}

export interface Contest {
  id: string;
  title: string;
  description: string;
  referralLink: string;
  prizeRub: number;
  prizeUsd: number;
  createdAt: number;
}

export enum ContestStep {
  LIST = 'list',
  REFERRAL = 'referral',
  PAYOUT = 'payout',
  FINAL = 'final',
  SUCCESS = 'success'
}

export type PayoutType = 'card' | 'trc20';

declare global {
  interface Window {
    Telegram?: {
      WebApp: {
        ready: () => void;
        expand: () => void;
        close: () => void;
        initDataUnsafe: {
          user?: TelegramUser;
        };
        HapticFeedback: {
          impactOccurred: (style: 'light' | 'medium' | 'heavy' | 'rigid' | 'soft') => void;
        };
      };
    };
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

const ADMIN_ID = 7946967720;
const STORAGE_KEY = 'beef_contests_v2';
const PARTICIPATION_KEY = 'user_participations_v2';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); // Default fallback

  // Participation Flow State
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin Form State
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }

    // Load Contests
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setContests(JSON.parse(saved));
    } else {
      const initial = [{
        id: 'default',
        title: 'Первый розыгрыш Beef',
        description: 'Участвуй и выиграй ценные призы!',
        prizeRub: 5000,
        prizeUsd: 55,
        referralLink: 'https://beef-way-one.com/c22082169',
        createdAt: Date.now()
      }];
      setContests(initial);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(initial));
    }

    // Load Participations
    const participations = localStorage.getItem(PARTICIPATION_KEY);
    if (participations) {
      setParticipatedIds(JSON.parse(participations));
    }

    // Fetch USD Rate
    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => {
        if (data.rates && data.rates.USD) {
          setUsdRate(data.rates.USD);
        }
      })
      .catch(() => console.log('Using default rate'));
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const saveContests = (newContests: Contest[]) => {
    setContests(newContests);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newContests));
    // NOTE: In a real app, you would send this to your API here.
  };

  const createContest = () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    saveContests([contest, ...contests]);
    setNewTitle('');
    setNewDesc('');
    setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = (id: string) => {
    saveContests(contests.filter(c => c.id !== id));
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
  };

  const startParticipation = (contest: Contest) => {
    if (participatedIds.includes(contest.id)) {
      setSelectedContest(contest);
      setStep(ContestStep.SUCCESS);
      return;
    }
    setSelectedContest(contest);
    setStep(ContestStep.REFERRAL);
    setCheckAttempts(0);
    setError(null);
  };

  const handleReferralCheck = () => {
    setIsChecking(true);
    setError(null);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    // 3 seconds cooldown as requested
    setTimeout(() => {
      setIsChecking(false);
      if (checkAttempts < 2) {
        setCheckAttempts(prev => prev + 1);
        setError("Проверь, зарегистрировался ли ты на Beef, или повтори попытку");
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('heavy');
      } else {
        setStep(ContestStep.PAYOUT);
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('soft');
      }
    }, 3000);
  };

  const validatePayout = () => {
    if (payoutType === 'card') {
      return /^\d{16}$/.test(payoutValue.replace(/\s/g, ''));
    }
    return /^T[a-zA-Z0-9]{33}$/.test(payoutValue.trim());
  };

  const handleFinalParticipate = () => {
    if (!selectedContest) return;
    setIsFinalizing(true);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    setTimeout(() => {
      const newParticipations = [...participatedIds, selectedContest.id];
      setParticipatedIds(newParticipations);
      localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(newParticipations));

      setIsFinalizing(false);
      setStep(ContestStep.SUCCESS);
      window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
    }, 1500);
  };

  const renderAdminPanel = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-24 bg-[var(--tg-theme-bg-color)]">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-2xl font-black flex items-center gap-2">
          <ShieldCheckIcon className="w-8 h-8 text-orange-500" />
          Админ-панель
        </h1>
        <button onClick={() => setView('user')} className="text-blue-500 font-bold p-2">Выйти</button>
      </div>

      <div className="bg-[var(--tg-theme-secondary-bg-color)] p-6 rounded-[2rem] space-y-4 mb-8 border border-gray-200 dark:border-gray-800 shadow-md">
        <h2 className="text-lg font-bold flex items-center gap-2">
          <PlusIcon className="w-5 h-5 text-blue-500" /> Создать розыгрыш
        </h2>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-50">Название</label>
            <input 
              placeholder="Введите название..." 
              value={newTitle} 
              onChange={e => setNewTitle(e.target.value)}
              className="w-full p-4 bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all"
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-50">Описание</label>
            <textarea 
              placeholder="О чем этот конкурс?" 
              value={newDesc} 
              onChange={e => setNewDesc(e.target.value)}
              className="w-full p-4 bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] rounded-2xl border border-gray-300 dark:border-gray-700 h-24 focus:border-blue-500 outline-none transition-all"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-black px-1 opacity-50">Приз (RUB)</label>
              <input 
                type="number"
                placeholder="Напр. 1000" 
                value={newPrizeRub} 
                onChange={e => setNewPrizeRub(e.target.value)}
                className="w-full p-4 bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-bold"
              />
            </div>
            <div className="space-y-1 opacity-60">
              <label className="text-[10px] uppercase font-black px-1">Приз (USD)</label>
              <div className="w-full p-4 bg-gray-100 dark:bg-gray-900 rounded-2xl border border-transparent font-bold">
                ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
              </div>
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-50">Ссылка Beef</label>
            <input 
              placeholder="https://..." 
              value={newLink} 
              onChange={e => setNewLink(e.target.value)}
              className="w-full p-4 bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all"
            />
          </div>
        </div>

        <button 
          onClick={createContest}
          disabled={!newTitle || !newLink || !newPrizeRub}
          className="w-full py-4 bg-blue-500 text-white rounded-[1.5rem] font-black text-lg active:scale-95 transition-transform disabled:opacity-30 shadow-lg shadow-blue-500/20"
        >
          ОПУБЛИКОВАТЬ
        </button>
      </div>

      <div className="space-y-4">
        <h2 className="text-lg font-bold px-1">Список событий</h2>
        {contests.length === 0 ? (
          <p className="text-center opacity-40 py-4">Список пуст</p>
        ) : (
          contests.map(c => (
            <div key={c.id} className="p-5 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl flex justify-between items-center border border-gray-100 dark:border-gray-800 shadow-sm">
              <div className="flex-1 mr-4">
                <p className="font-black text-lg leading-tight">{c.title}</p>
                <p className="text-xs font-bold text-blue-500">{c.prizeRub?.toLocaleString()} ₽ (~${c.prizeUsd})</p>
              </div>
              <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/10 rounded-2xl active:scale-90 transition-all">
                <TrashIcon className="w-6 h-6" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );

  const renderContestList = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-10">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-600/30">
            <TrophyIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-xl font-black leading-none mb-1">Beef Contest</h1>
            <p className="text-[10px] uppercase tracking-widest font-black text-[var(--tg-theme-hint-color)]">Активные события</p>
          </div>
        </div>
        {isAdmin && (
          <button 
            onClick={() => setView('admin')}
            className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl active:scale-90 transition-transform"
          >
            <ShieldCheckIcon className="w-6 h-6 text-blue-600" />
          </button>
        )}
      </div>

      <div className="space-y-5">
        {contests.length === 0 ? (
          <div className="text-center py-20 text-[var(--tg-theme-hint-color)]">
            <UserGroupIcon className="w-20 h-20 mx-auto mb-4 opacity-10" />
            <p className="font-bold text-lg">Пока ничего нет</p>
          </div>
        ) : (
          contests.map(c => {
            const hasJoined = participatedIds.includes(c.id);
            return (
              <div 
                key={c.id} 
                onClick={() => startParticipation(c)}
                className={`p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2rem] border-2 shadow-sm active:scale-[0.98] transition-all relative overflow-hidden group ${hasJoined ? 'border-green-500/30' : 'border-transparent'}`}
              >
                {hasJoined && (
                  <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase tracking-tighter shadow-sm flex items-center gap-1 z-10">
                    <CheckBadgeIcon className="w-3 h-3" /> Участвую
                  </div>
                )}

                <div className="flex items-start justify-between mb-2">
                  <h3 className="text-xl font-black pr-12 leading-tight">{c.title}</h3>
                </div>

                <div className="flex items-center gap-2 mb-4 bg-blue-500/10 dark:bg-blue-500/5 w-fit px-3 py-1 rounded-full">
                  <BanknotesIcon className="w-4 h-4 text-blue-500" />
                  <span className="text-sm font-black text-blue-500">
                    {c.prizeRub?.toLocaleString() || 0} ₽ 
                    <span className="opacity-50 mx-1 font-normal">/</span>
                    ${c.prizeUsd || 0}
                  </span>
                </div>

                <p className="text-sm text-[var(--tg-theme-hint-color)] mb-5 line-clamp-2 font-medium leading-snug">
                  {c.description}
                </p>

                <div className="flex items-center justify-between">
                  <span className={`text-[10px] uppercase tracking-widest font-black flex items-center gap-1 ${hasJoined ? 'text-green-500' : 'text-blue-600'}`}>
                    {hasJoined ? 'Вы в игре' : 'Попробовать удачу'} <ArrowRightIcon className="w-3 h-3" />
                  </span>
                  <div className="flex -space-x-2">
                    {[1, 2, 3].map(i => (
                      <div key={i} className="w-7 h-7 bg-blue-100 dark:bg-blue-900/30 rounded-full border-2 border-[var(--tg-theme-secondary-bg-color)] flex items-center justify-center">
                        <UserGroupIcon className="w-3.5 h-3.5 text-blue-500" />
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );

  const renderReferralStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <button onClick={() => setStep(ContestStep.LIST)} className="mb-6 flex items-center gap-1 text-blue-600 font-black text-sm uppercase tracking-wider">
        <ChevronLeftIcon className="w-5 h-5" /> Назад
      </button>
      <div className="flex-1 flex flex-col justify-center items-center text-center space-y-8">
        <div className="relative">
          <div className="absolute inset-0 bg-blue-500/20 blur-3xl rounded-full"></div>
          <div className="relative w-28 h-28 bg-white dark:bg-gray-900 rounded-[2.5rem] flex items-center justify-center shadow-2xl border border-blue-500/10">
            <LinkIcon className="w-14 h-14 text-blue-600" />
          </div>
        </div>
        <div className="space-y-4">
          <h1 className="text-3xl font-black leading-tight px-4">{selectedContest?.title}</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg px-6 font-medium leading-relaxed">
            Для участия в розыгрыше <span className="text-blue-600 font-black">{selectedContest?.prizeRub?.toLocaleString()} ₽</span> необходимо быть рефералом.
          </p>
        </div>

        <a 
          href={selectedContest?.referralLink} 
          target="_blank"
          className="w-full p-5 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-[2rem] flex items-center justify-between shadow-xl shadow-blue-500/30 active:scale-[0.98] transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center">
              <LinkIcon className="w-7 h-7" />
            </div>
            <span className="font-black text-lg tracking-tight uppercase">РЕГИСТРАЦИЯ BEEF</span>
          </div>
          <ArrowRightIcon className="w-6 h-6 mr-1" />
        </a>

        {error && (
          <div className="flex items-center gap-3 p-4 bg-red-50 dark:bg-red-900/10 text-red-600 rounded-2xl text-sm animate-shake border border-red-100 dark:border-red-900/20 shadow-sm">
            <ExclamationCircleIcon className="w-6 h-6 flex-shrink-0" />
            <p className="text-left leading-tight font-black">{error}</p>
          </div>
        )}
      </div>

      <button
        disabled={isChecking}
        onClick={handleReferralCheck}
        className="w-full py-5 rounded-[2rem] font-black text-xl btn-primary flex items-center justify-center gap-3 disabled:opacity-50 transition-all shadow-xl shadow-blue-500/20 active:scale-95"
      >
        {isChecking ? (
          <>
            <ClockIcon className="w-6 h-6 animate-spin" />
            ПРОВЕРЯЕМ...
          </>
        ) : (
          'ПРОВЕРИТЬ'
        )}
      </button>
    </div>
  );

  const renderPayoutStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <div className="flex-1 space-y-8 pt-8">
        <div className="space-y-3">
          <h1 className="text-4xl font-black tracking-tight">ВЫПЛАТА</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-snug font-medium">
            Укажите реквизиты, на которые мы отправим приз в случае победы.
          </p>
        </div>

        <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-[1.8rem] border border-gray-100 dark:border-gray-800 shadow-inner">
          <button 
            onClick={() => { setPayoutType('card'); setPayoutValue(''); }}
            className={`flex-1 py-4 rounded-2xl text-sm font-black transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-xl text-blue-600' : 'opacity-40'}`}
          >
            КАРТА
          </button>
          <button 
            onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }}
            className={`flex-1 py-4 rounded-2xl text-sm font-black transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-xl text-green-600' : 'opacity-40'}`}
          >
            USDT (TRC20)
          </button>
        </div>

        <div className="space-y-4">
          <div className="relative group">
            <div className="absolute left-6 top-1/2 -translate-y-1/2 transition-colors group-focus-within:text-blue-500">
              {payoutType === 'card' ? <CreditCardIcon className="w-7 h-7 text-gray-400" /> : <CurrencyDollarIcon className="w-7 h-7 text-green-500" />}
            </div>
            <input 
              type="text"
              placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес TRC20 кошелька"}
              value={payoutValue}
              onChange={(e) => setPayoutValue(e.target.value)}
              maxLength={payoutType === 'card' ? 19 : 42}
              className="w-full py-6 pl-16 pr-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2rem] font-mono text-xl border-2 border-transparent focus:border-blue-500 transition-all outline-none shadow-sm"
            />
          </div>
          <div className="px-6">
            <p className="text-[10px] text-blue-600 uppercase tracking-widest font-black opacity-80">
              {payoutType === 'card' ? "Введите 16 цифр вашей карты без пробелов" : "Убедитесь, что адрес в сети Tron"}
            </p>
          </div>
        </div>
      </div>

      <button
        disabled={!validatePayout()}
        onClick={() => setStep(ContestStep.FINAL)}
        className="w-full py-6 rounded-[2rem] font-black text-2xl btn-primary disabled:opacity-20 disabled:grayscale transition-all shadow-2xl shadow-blue-500/30 active:scale-95 mb-4"
      >
        ДАЛЕЕ
      </button>
    </div>
  );

  const renderFinalStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center">
      <div className="flex-1 flex flex-col justify-center space-y-10">
        <div className="relative w-36 h-36 mx-auto">
          <div className="absolute inset-0 bg-blue-500/30 rounded-[3rem] blur-3xl animate-pulse"></div>
          <div className="relative w-full h-full bg-white dark:bg-gray-900 rounded-[3rem] flex items-center justify-center border-2 border-blue-500/20 shadow-2xl">
            <CheckBadgeIcon className="w-20 h-20 text-blue-600" />
          </div>
        </div>
        <div className="space-y-4">
          <h1 className="text-4xl font-black tracking-tight leading-none uppercase">ПОЧТИ ВСЁ!</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-tight px-10 font-medium">
            Жми на кнопку ниже, чтобы занять свое место в розыгрыше приза <span className="text-blue-600 font-black">{selectedContest?.prizeRub?.toLocaleString()} ₽</span>
          </p>
        </div>
        <div className="p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2rem] mx-4 border border-blue-500/10 shadow-inner">
          <p className="text-[10px] text-blue-600 uppercase tracking-widest font-black mb-2 opacity-60">Ваш счет для зачисления:</p>
          <p className="font-mono text-lg break-all font-black text-[var(--tg-theme-text-color)]">{payoutValue}</p>
        </div>
      </div>

      <button
        disabled={isFinalizing}
        onClick={handleFinalParticipate}
        className="w-full py-7 rounded-[2.5rem] font-black text-2xl btn-primary shadow-[0_20px_40px_-10px_rgba(36,129,204,0.5)] flex items-center justify-center gap-4 active:scale-95 transition-all mb-4"
      >
        {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin" /> : 'ВСТУПИТЬ В ИГРУ'}
      </button>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center justify-center space-y-10">
      <div className="relative">
        <div className="absolute inset-0 bg-green-500/20 blur-[5rem] rounded-full animate-pulse"></div>
        <div className="relative w-44 h-44 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center mx-auto text-white shadow-[0_25px_60px_-15px_rgba(16,185,129,0.5)]">
          <CheckBadgeIcon className="w-24 h-24 drop-shadow-xl" />
        </div>
      </div>
      <div className="space-y-4">
        <h1 className="text-4xl font-black tracking-tighter uppercase leading-none">ВЫ В СПИСКЕ!</h1>
        <p className="text-[var(--tg-theme-hint-color)] px-10 text-xl leading-relaxed font-medium">
          Твоя заявка принята. Итоги будут подведены в нашем канале. Удачи!
        </p>
      </div>
      <button 
        onClick={() => setStep(ContestStep.LIST)}
        className="mt-12 font-black text-blue-600 text-lg hover:opacity-70 transition-all flex items-center justify-center gap-2 mx-auto active:scale-90"
      >
        <ChevronLeftIcon className="w-6 h-6" /> К списку розыгрышей
      </button>
    </div>
  );

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] select-none overflow-hidden text-[var(--tg-theme-text-color)] font-sans">
      {view === 'admin' ? renderAdminPanel() : (
        <>
          {step === ContestStep.LIST && renderContestList()}
          {step === ContestStep.REFERRAL && renderReferralStep()}
          {step === ContestStep.PAYOUT && renderPayoutStep()}
          {step === ContestStep.FINAL && renderFinalStep()}
          {step === ContestStep.SUCCESS && renderSuccess()}
        </>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;700;900&display=swap');

        body {
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
        }

        @keyframes fade-in {
          from { opacity: 0; transform: scale(0.98) translateY(10px); }
          to { opacity: 1; transform: scale(1) translateY(0); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-8px); }
          75% { transform: translateX(8px); }
        }
        .animate-fade-in { animation: fade-in 0.6s cubic-bezier(0.23, 1, 0.32, 1) forwards; }
        .animate-shake { animation: shake 0.15s ease-in-out 0s 2; }

        .shadow-3xl {
          box-shadow: 0 25px 60px -15px rgba(16, 185, 129, 0.4);
        }

        .btn-primary {
          background: linear-gradient(135deg, var(--tg-theme-button-color, #2481cc) 0%, #1e6fb0 100%);
          border: none;
        }

        input::placeholder, textarea::placeholder {
          opacity: 0.3;
          font-weight: 500;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

const ADMIN_ID = 7946967720;
// Используем публичный анонимный ключ-значение для демонстрации "общих" данных.
// В реальном проекте на Vercel лучше использовать Vercel KV.
const DB_URL = 'https://kvdb.io/A9S7nJm6k5Lp3Q2w1E4rT7/beef_contests_global'; 
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);

  // Participation Flow State
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin Form State
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    try {
      const res = await fetch(DB_URL);
      if (res.ok) {
        const data = await res.json();
        setContests(Array.isArray(data) ? data : []);
      }
    } catch (e) {
      console.error("Failed to fetch contests", e);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    try {
      await fetch(DB_URL, {
        method: 'POST',
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Failed to save contests globally", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }

    fetchContests();

    const participations = localStorage.getItem(PARTICIPATION_KEY);
    if (participations) {
      setParticipatedIds(JSON.parse(participations));
    }

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => {
        if (data.rates?.USD) setUsdRate(data.rates.USD);
      });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);

    setNewTitle('');
    setNewDesc('');
    setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
  };

  const startParticipation = (contest: Contest) => {
    setSelectedContest(contest);
    if (participatedIds.includes(contest.id)) {
      setStep(ContestStep.SUCCESS);
      return;
    }
    setStep(ContestStep.REFERRAL);
    setCheckAttempts(0);
    setError(null);
  };

  const handleReferralCheck = () => {
    setIsChecking(true);
    setError(null);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    setTimeout(() => {
      setIsChecking(false);
      if (checkAttempts < 2) {
        setCheckAttempts(prev => prev + 1);
        setError("Проверь, зарегистрировался ли ты на Beef, или повтори попытку");
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('heavy');
      } else {
        setStep(ContestStep.PAYOUT);
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('soft');
      }
    }, 3000); // 3 seconds cooldown
  };

  const validatePayout = () => {
    if (payoutType === 'card') return /^\d{16,19}$/.test(payoutValue.replace(/\s/g, ''));
    return /^T[a-zA-Z0-9]{33}$/.test(payoutValue.trim());
  };

  const handleFinalParticipate = () => {
    if (!selectedContest) return;
    setIsFinalizing(true);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    setTimeout(() => {
      const newParticipations = [...participatedIds, selectedContest.id];
      setParticipatedIds(newParticipations);
      localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(newParticipations));

      setIsFinalizing(false);
      setStep(ContestStep.SUCCESS);
      window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
    }, 1500);
  };

  const renderAdminPanel = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-24 bg-[var(--tg-theme-bg-color)]">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-2xl font-black flex items-center gap-2">
          <ShieldCheckIcon className="w-8 h-8 text-orange-500" />
          Админ-центр
        </h1>
        <button onClick={() => setView('user')} className="text-blue-500 font-bold p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">Выйти</button>
      </div>

      <div className="bg-[var(--tg-theme-secondary-bg-color)] p-6 rounded-[2rem] space-y-4 mb-8 border border-gray-200 dark:border-gray-800 shadow-lg">
        <h2 className="text-lg font-bold flex items-center gap-2">
          <PlusIcon className="w-5 h-5 text-blue-500" /> Создать общий розыгрыш
        </h2>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Заголовок</label>
            <input 
              placeholder="Название розыгрыша" 
              value={newTitle} 
              onChange={e => setNewTitle(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-medium"
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Описание</label>
            <textarea 
              placeholder="Условия или подробности..." 
              value={newDesc} 
              onChange={e => setNewDesc(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 h-24 focus:border-blue-500 outline-none transition-all font-medium"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-black px-1 opacity-60">Приз (RUB)</label>
              <input 
                type="number"
                placeholder="5000" 
                value={newPrizeRub} 
                onChange={e => setNewPrizeRub(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-black text-blue-600"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-black px-1 opacity-30">Приз (USD)</label>
              <div className="w-full p-4 bg-gray-100 dark:bg-gray-900 rounded-2xl border border-transparent font-black text-gray-500">
                ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
              </div>
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Ссылка Beef</label>
            <input 
              placeholder="https://beef-way-one.com/..." 
              value={newLink} 
              onChange={e => setNewLink(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-medium"
            />
          </div>
        </div>

        <button 
          onClick={createContest}
          disabled={!newTitle || !newLink || !newPrizeRub}
          className="w-full py-4 bg-blue-600 text-white rounded-[1.5rem] font-black text-lg active:scale-95 transition-all disabled:opacity-20 shadow-xl shadow-blue-600/20"
        >
          ОПУБЛИКОВАТЬ ДЛЯ ВСЕХ
        </button>
      </div>

      <div className="space-y-4">
        <h2 className="text-lg font-bold px-1">Управление</h2>
        {contests.map(c => (
          <div key={c.id} className="p-5 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl flex justify-between items-center border border-gray-200 dark:border-gray-800 shadow-sm">
            <div className="flex-1 mr-4">
              <p className="font-black text-lg leading-tight">{c.title}</p>
              <p className="text-xs font-bold text-blue-500">{c.prizeRub?.toLocaleString()} ₽ / ${c.prizeUsd}</p>
            </div>
            <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/10 rounded-2xl active:scale-90 transition-all">
              <TrashIcon className="w-6 h-6" />
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  const renderContestList = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-10">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <div className="w-14 h-14 bg-blue-600 rounded-[1.25rem] flex items-center justify-center text-white shadow-2xl shadow-blue-600/40">
            <TrophyIcon className="w-8 h-8" />
          </div>
          <div>
            <h1 className="text-2xl font-black leading-none mb-1">Beef Contest</h1>
            <p className="text-[10px] uppercase tracking-[0.2em] font-black text-blue-500">Live Events</p>
          </div>
        </div>
        {isAdmin && (
          <button onClick={() => setView('admin')} className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-2xl active:scale-90 transition-transform">
            <ShieldCheckIcon className="w-7 h-7 text-blue-600" />
          </button>
        )}
      </div>

      {isLoading ? (
        <div className="flex-1 flex items-center justify-center opacity-30">
          <ClockIcon className="w-10 h-10 animate-spin" />
        </div>
      ) : (
        <div className="space-y-5">
          {contests.length === 0 ? (
            <div className="text-center py-20 opacity-20">
              <UserGroupIcon className="w-24 h-24 mx-auto mb-4" />
              <p className="font-black text-xl">Розыгрышей пока нет</p>
            </div>
          ) : (
            contests.map(c => {
              const hasJoined = participatedIds.includes(c.id);
              return (
                <div 
                  key={c.id} 
                  onClick={() => startParticipation(c)}
                  className={`p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] border-2 shadow-sm active:scale-[0.98] transition-all relative overflow-hidden group ${hasJoined ? 'border-green-500/30' : 'border-transparent'}`}
                >
                  {hasJoined && (
                    <div className="absolute top-0 right-0 bg-green-500 text-white px-5 py-2 rounded-bl-3xl text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center gap-1.5 z-10">
                      <CheckBadgeIcon className="w-4 h-4" /> ВЫ УЧАСТВУЕТЕ
                    </div>
                  )}

                  <h3 className="text-2xl font-black pr-12 leading-tight mb-3">{c.title}</h3>

                  <div className="flex items-center gap-2 mb-4 bg-blue-600/10 w-fit px-4 py-1.5 rounded-full border border-blue-600/5">
                    <BanknotesIcon className="w-5 h-5 text-blue-600" />
                    <span className="text-base font-black text-blue-600">
                      {c.prizeRub?.toLocaleString()} ₽ 
                      <span className="opacity-30 mx-2 font-normal">|</span>
                      ${c.prizeUsd}
                    </span>
                  </div>

                  <p className="text-sm text-[var(--tg-theme-hint-color)] mb-6 line-clamp-2 font-medium leading-relaxed">
                    {c.description}
                  </p>

                  <div className="flex items-center justify-between">
                    <span className={`text-[10px] uppercase tracking-[0.2em] font-black flex items-center gap-2 ${hasJoined ? 'text-green-500' : 'text-blue-600'}`}>
                      {hasJoined ? 'СТАТУС: ПОДТВЕРЖДЕНО' : 'УЧАСТВОВАТЬ СЕЙЧАС'} <ArrowRightIcon className="w-3.5 h-3.5" />
                    </span>
                    <div className="flex -space-x-3">
                      {[1, 2, 3].map(i => (
                        <div key={i} className="w-9 h-9 bg-gray-200 dark:bg-gray-800 rounded-full border-4 border-[var(--tg-theme-secondary-bg-color)] flex items-center justify-center">
                          <UserGroupIcon className="w-4 h-4 text-gray-400" />
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}
    </div>
  );

  const renderReferralStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <button onClick={() => setStep(ContestStep.LIST)} className="mb-6 flex items-center gap-2 text-blue-600 font-black text-xs uppercase tracking-widest">
        <ChevronLeftIcon className="w-5 h-5" /> Назад к списку
      </button>
      <div className="flex-1 flex flex-col justify-center items-center text-center space-y-10">
        <div className="relative">
          <div className="absolute inset-0 bg-blue-500/20 blur-[4rem] rounded-full"></div>
          <div className="relative w-32 h-32 bg-white dark:bg-gray-900 rounded-[3rem] flex items-center justify-center shadow-2xl border border-blue-500/10">
            <LinkIcon className="w-16 h-16 text-blue-600" />
          </div>
        </div>
        <div className="space-y-4 px-4">
          <h1 className="text-3xl font-black leading-tight">{selectedContest?.title}</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg font-medium leading-relaxed opacity-80">
            Для участия в розыгрыше <span className="text-blue-600 font-black">{selectedContest?.prizeRub?.toLocaleString()} ₽</span> вы должны быть в команде Beef.
          </p>
        </div>

        <a 
          href={selectedContest?.referralLink} 
          target="_blank"
          className="w-full p-6 bg-gradient-to-br from-blue-600 to-blue-700 text-white rounded-[2.5rem] flex items-center justify-between shadow-2xl shadow-blue-600/30 active:scale-[0.97] transition-all"
        >
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md">
              <LinkIcon className="w-8 h-8" />
            </div>
            <span className="font-black text-xl tracking-tight">РЕГИСТРАЦИЯ BEEF</span>
          </div>
          <ArrowRightIcon className="w-7 h-7 mr-2 opacity-50" />
        </a>

        {error && (
          <div className="flex items-center gap-3 p-5 bg-red-50 dark:bg-red-900/10 text-red-600 rounded-3xl text-sm animate-shake border border-red-100 dark:border-red-900/20">
            <ExclamationCircleIcon className="w-7 h-7 flex-shrink-0" />
            <p className="text-left leading-tight font-black">{error}</p>
          </div>
        )}
      </div>

      <button
        disabled={isChecking}
        onClick={handleReferralCheck}
        className="w-full py-6 rounded-[2.5rem] font-black text-2xl btn-primary flex items-center justify-center gap-4 disabled:opacity-50 transition-all shadow-2xl shadow-blue-600/20 active:scale-95 mb-4"
      >
        {isChecking ? <ClockIcon className="w-8 h-8 animate-spin" /> : 'ПРОВЕРИТЬ РЕГИСТРАЦИЮ'}
      </button>
    </div>
  );

  const renderPayoutStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <div className="flex-1 space-y-10 pt-10">
        <div className="space-y-4">
          <h1 className="text-5xl font-black tracking-tighter">ВЫПЛАТА</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-xl leading-snug font-medium opacity-80">
            Укажите реквизиты. Если вы выиграете, мы отправим деньги сюда.
          </p>
        </div>

        <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2.5 rounded-[2.2rem] border border-gray-100 dark:border-gray-800 shadow-inner">
          <button 
            onClick={() => { setPayoutType('card'); setPayoutValue(''); }}
            className={`flex-1 py-5 rounded-3xl text-sm font-black tracking-widest transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-2xl text-blue-600' : 'opacity-30'}`}
          >
            КАРТА (RUB)
          </button>
          <button 
            onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }}
            className={`flex-1 py-5 rounded-3xl text-sm font-black tracking-widest transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-2xl text-green-600' : 'opacity-30'}`}
          >
            USDT (TRC20)
          </button>
        </div>

        <div className="space-y-6">
          <div className="relative group">
            <div className="absolute left-7 top-1/2 -translate-y-1/2 transition-all group-focus-within:text-blue-600">
              {payoutType === 'card' ? <CreditCardIcon className="w-8 h-8 text-gray-300" /> : <CurrencyDollarIcon className="w-8 h-8 text-green-500" />}
            </div>
            <input 
              type="text"
              placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька TRC20"}
              value={payoutValue}
              onChange={(e) => setPayoutValue(e.target.value)}
              className="w-full py-7 pl-20 pr-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] font-mono text-2xl border-2 border-transparent focus:border-blue-600 transition-all outline-none shadow-sm placeholder:opacity-20"
            />
          </div>
          <div className="px-8">
            <p className="text-[11px] text-blue-600 uppercase tracking-[0.25em] font-black opacity-60">
              {payoutType === 'card' ? "Введите полный номер карты" : "Сеть TRON (TRC20) обязательна"}
            </p>
          </div>
        </div>
      </div>

      <button
        disabled={!validatePayout()}
        onClick={() => setStep(ContestStep.FINAL)}
        className="w-full py-7 rounded-[2.5rem] font-black text-2xl btn-primary disabled:opacity-10 disabled:grayscale transition-all shadow-2xl shadow-blue-600/30 active:scale-95 mb-6"
      >
        ПОДТВЕРДИТЬ
      </button>
    </div>
  );

  const renderFinalStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center">
      <div className="flex-1 flex flex-col justify-center space-y-12">
        <div className="relative w-40 h-40 mx-auto">
          <div className="absolute inset-0 bg-blue-600/30 rounded-[3.5rem] blur-[5rem] animate-pulse"></div>
          <div className="relative w-full h-full bg-white dark:bg-gray-900 rounded-[3.5rem] flex items-center justify-center border-2 border-blue-600/20 shadow-2xl">
            <CheckBadgeIcon className="w-24 h-24 text-blue-600" />
          </div>
        </div>
        <div className="space-y-5 px-6">
          <h1 className="text-5xl font-black tracking-tighter leading-none uppercase">ГОТОВО!</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-xl leading-relaxed font-medium opacity-80">
            Остался один клик до участия в <br/> <span className="text-blue-600 font-black italic">{selectedContest?.title}</span>
          </p>
        </div>
        <div className="p-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[3rem] mx-4 border border-blue-600/10 shadow-inner">
          <p className="text-[11px] text-blue-600 uppercase tracking-widest font-black mb-3 opacity-40">РЕКВИЗИТЫ ДЛЯ ПРИЗА:</p>
          <p className="font-mono text-xl break-all font-black text-[var(--tg-theme-text-color)]">{payoutValue}</p>
        </div>
      </div>

      <button
        disabled={isFinalizing}
        onClick={handleFinalParticipate}
        className="w-full py-8 rounded-[3rem] font-black text-3xl btn-primary shadow-[0_30px_60px_-15px_rgba(36,129,204,0.6)] flex items-center justify-center gap-5 active:scale-95 transition-all mb-6"
      >
        {isFinalizing ? <ClockIcon className="w-10 h-10 animate-spin" /> : 'ВСТУПИТЬ'}
      </button>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center justify-center space-y-12">
      <div className="relative">
        <div className="absolute inset-0 bg-green-500/30 blur-[6rem] rounded-full animate-pulse"></div>
        <div className="relative w-48 h-48 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center mx-auto text-white shadow-[0_30px_70px_-20px_rgba(16,185,129,0.6)]">
          <CheckBadgeIcon className="w-28 h-28 drop-shadow-2xl" />
        </div>
      </div>
      <div className="space-y-5">
        <h1 className="text-5xl font-black tracking-tighter uppercase leading-none">УДАЧИ!</h1>
        <p className="text-[var(--tg-theme-hint-color)] px-12 text-2xl leading-relaxed font-medium">
          Вы уже участвуете в этом розыгрыше. Результаты скоро в канале!
        </p>
      </div>
      <button 
        onClick={() => setStep(ContestStep.LIST)}
        className="mt-16 font-black text-blue-600 text-xl hover:opacity-70 transition-all flex items-center justify-center gap-3 mx-auto active:scale-90"
      >
        <ChevronLeftIcon className="w-7 h-7" /> К ДРУГИМ РОЗЫГРЫШАМ
      </button>
    </div>
  );

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] select-none overflow-hidden text-[var(--tg-theme-text-color)] font-sans">
      {view === 'admin' ? renderAdminPanel() : (
        <>
          {step === ContestStep.LIST && renderContestList()}
          {step === ContestStep.REFERRAL && renderReferralStep()}
          {step === ContestStep.PAYOUT && renderPayoutStep()}
          {step === ContestStep.FINAL && renderFinalStep()}
          {step === ContestStep.SUCCESS && renderSuccess()}
        </>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;700;800&display=swap');

        body {
          font-family: 'Plus Jakarta Sans', sans-serif;
        }

        @keyframes fade-in {
          from { opacity: 0; transform: scale(0.97) translateY(20px); }
          to { opacity: 1; transform: scale(1) translateY(0); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-10px); }
          75% { transform: translateX(10px); }
        }
        .animate-fade-in { animation: fade-in 0.7s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out 0s 3; }

        .btn-primary {
          background: linear-gradient(135deg, #2481cc 0%, #1a65a3 100%);
          border: none;
        }

        input::placeholder, textarea::placeholder {
          color: inherit;
          opacity: 0.15;
          font-weight: 700;
        }

        input, textarea {
          -webkit-appearance: none;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

// --- НАСТРОЙКИ БАЗЫ ДАННЫХ VERCEL KV ---
// Если ты уже на Vercel, эти переменные могут подхватиться автоматически, 
// но для надежности вставь сюда значения из раздела REST API в панели Vercel.
const KV_REST_API_URL = process.env.KV_REST_API_URL || ''; 
const KV_REST_API_TOKEN = process.env.KV_REST_API_TOKEN || '';
const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);

  // Participation Flow State
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin Form State
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    try {
      if (!KV_REST_API_URL || !KV_REST_API_TOKEN) {
        console.warn("KV_REST_API not configured. Using local storage.");
        const local = localStorage.getItem(DB_KEY);
        setContests(local ? JSON.parse(local) : []);
        return;
      }

      const res = await fetch(`${KV_REST_API_URL}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${KV_REST_API_TOKEN}` }
      });

      const data = await res.json();
      if (data.result) {
        const parsed = JSON.parse(data.result);
        setContests(Array.isArray(parsed) ? parsed : []);
      }
    } catch (e) {
      console.error("Database error:", e);
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    if (!KV_REST_API_URL || !KV_REST_API_TOKEN) return;

    try {
      await fetch(`${KV_REST_API_URL}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${KV_REST_API_TOKEN}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Failed to sync with Vercel KV:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }

    fetchContests();

    const participations = localStorage.getItem(PARTICIPATION_KEY);
    if (participations) {
      setParticipatedIds(JSON.parse(participations));
    }

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => {
        if (data.rates?.USD) setUsdRate(data.rates.USD);
      });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);

    setNewTitle('');
    setNewDesc('');
    setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('light');
  };

  const startParticipation = (contest: Contest) => {
    setSelectedContest(contest);
    if (participatedIds.includes(contest.id)) {
      setStep(ContestStep.SUCCESS);
      return;
    }
    setStep(ContestStep.REFERRAL);
    setCheckAttempts(0);
    setError(null);
  };

  const handleReferralCheck = () => {
    setIsChecking(true);
    setError(null);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    setTimeout(() => {
      setIsChecking(false);
      if (checkAttempts < 1) { // 2 attempts total
        setCheckAttempts(prev => prev + 1);
        setError("Регистрация не найдена. Попробуйте еще раз или проверьте линк.");
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('heavy');
      } else {
        setStep(ContestStep.PAYOUT);
        window.Telegram?.WebApp?.HapticFeedback.impactOccurred('soft');
      }
    }, 3000);
  };

  const validatePayout = () => {
    if (payoutType === 'card') return /^\d{16,19}$/.test(payoutValue.replace(/\s/g, ''));
    return /^T[a-zA-Z0-9]{33}$/.test(payoutValue.trim());
  };

  const handleFinalParticipate = () => {
    if (!selectedContest) return;
    setIsFinalizing(true);
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');

    setTimeout(() => {
      const newParticipations = [...participatedIds, selectedContest.id];
      setParticipatedIds(newParticipations);
      localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(newParticipations));
      setIsFinalizing(false);
      setStep(ContestStep.SUCCESS);
    }, 1500);
  };

  const renderAdminPanel = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-24 bg-[var(--tg-theme-bg-color)]">
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-2xl font-black flex items-center gap-2">
          <ShieldCheckIcon className="w-8 h-8 text-orange-500" />
          Админ-центр
        </h1>
        <button onClick={() => setView('user')} className="text-blue-500 font-bold p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">На главную</button>
      </div>

      <div className="bg-[var(--tg-theme-secondary-bg-color)] p-6 rounded-[2rem] space-y-4 mb-8 border border-gray-200 dark:border-gray-800 shadow-xl">
        <h2 className="text-lg font-bold flex items-center gap-2 text-[var(--tg-theme-text-color)]">
          <PlusIcon className="w-5 h-5 text-blue-500" /> Новый розыгрыш
        </h2>

        <div className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Название</label>
            <input 
              placeholder="Напр. Зимний куш" 
              value={newTitle} 
              onChange={e => setNewTitle(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-semibold"
            />
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Описание</label>
            <textarea 
              placeholder="Коротко об условиях..." 
              value={newDesc} 
              onChange={e => setNewDesc(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 h-20 focus:border-blue-500 outline-none transition-all font-medium"
            />
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-black px-1 opacity-60">Приз (RUB)</label>
              <input 
                type="number"
                placeholder="1000" 
                value={newPrizeRub} 
                onChange={e => setNewPrizeRub(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-950 text-blue-600 dark:text-blue-400 rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-black"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] uppercase font-black px-1 opacity-30">В долларах</label>
              <div className="w-full p-4 bg-gray-50 dark:bg-gray-900 rounded-2xl border border-transparent font-black text-gray-400">
                ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
              </div>
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] uppercase font-black px-1 opacity-60">Ссылка Beef</label>
            <input 
              placeholder="https://..." 
              value={newLink} 
              onChange={e => setNewLink(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 text-black dark:text-white rounded-2xl border border-gray-300 dark:border-gray-700 focus:border-blue-500 outline-none transition-all font-medium"
            />
          </div>
        </div>

        <button 
          onClick={createContest}
          disabled={!newTitle || !newLink || !newPrizeRub}
          className="w-full py-4 bg-blue-600 text-white rounded-[1.5rem] font-black text-lg active:scale-95 transition-all disabled:opacity-30 shadow-lg shadow-blue-600/20"
        >
          СОЗДАТЬ ОБЛАЧНЫЙ РОЗЫГРЫШ
        </button>
      </div>

      <div className="space-y-3">
        <h2 className="text-lg font-bold px-1 opacity-80">Активные события ({contests.length})</h2>
        {contests.map(c => (
          <div key={c.id} className="p-4 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl flex justify-between items-center border border-gray-200 dark:border-gray-800">
            <div className="flex-1 mr-4 overflow-hidden">
              <p className="font-black text-base truncate">{c.title}</p>
              <p className="text-[10px] font-bold text-blue-500 uppercase">{c.prizeRub?.toLocaleString()} RUB</p>
            </div>
            <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/10 rounded-2xl active:scale-90 transition-all">
              <TrashIcon className="w-5 h-5" />
            </button>
          </div>
        ))}
      </div>
    </div>
  );

  const renderContestList = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in overflow-y-auto pb-10">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-600/30">
            <TrophyIcon className="w-7 h-7" />
          </div>
          <div>
            <h1 className="text-xl font-black leading-none mb-1">Beef Contest</h1>
            <p className="text-[10px] uppercase font-black text-blue-500 tracking-wider">Розыгрыши для своих</p>
          </div>
        </div>
        {isAdmin && (
          <button onClick={() => setView('admin')} className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl">
            <ShieldCheckIcon className="w-6 h-6 text-blue-600" />
          </button>
        )}
      </div>

      {isLoading ? (
        <div className="flex-1 flex flex-col items-center justify-center opacity-40 gap-4">
          <ClockIcon className="w-12 h-12 animate-spin text-blue-600" />
          <p className="font-black text-xs uppercase tracking-[0.2em]">Загрузка базы...</p>
        </div>
      ) : (
        <div className="space-y-5">
          {contests.length === 0 ? (
            <div className="text-center py-20 opacity-20 flex flex-col items-center">
              <UserGroupIcon className="w-20 h-20 mb-4" />
              <p className="font-black text-lg uppercase italic">Событий нет</p>
            </div>
          ) : (
            contests.map(c => {
              const hasJoined = participatedIds.includes(c.id);
              return (
                <div 
                  key={c.id} 
                  onClick={() => startParticipation(c)}
                  className={`p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] border-2 shadow-sm active:scale-[0.98] transition-all relative overflow-hidden group ${hasJoined ? 'border-green-500/30' : 'border-transparent'}`}
                >
                  {hasJoined && (
                    <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase tracking-tighter shadow-lg flex items-center gap-1 z-10">
                      <CheckBadgeIcon className="w-3.5 h-3.5" /> В ИГРЕ
                    </div>
                  )}

                  <h3 className="text-xl font-black pr-12 leading-tight mb-3">{c.title}</h3>

                  <div className="flex items-center gap-2 mb-4 bg-blue-600/10 w-fit px-4 py-1.5 rounded-full">
                    <BanknotesIcon className="w-4 h-4 text-blue-600" />
                    <span className="text-sm font-black text-blue-600">
                      {c.prizeRub?.toLocaleString()} ₽ 
                      <span className="opacity-30 mx-2">/</span>
                      ${c.prizeUsd}
                    </span>
                  </div>

                  <p className="text-xs text-[var(--tg-theme-hint-color)] mb-5 line-clamp-2 font-medium leading-relaxed">
                    {c.description}
                  </p>

                  <div className="flex items-center justify-between">
                    <span className={`text-[9px] uppercase tracking-widest font-black flex items-center gap-2 ${hasJoined ? 'text-green-500' : 'text-blue-600'}`}>
                      {hasJoined ? 'ВАША ЗАЯВКА ПРИНЯТА' : 'УЧАСТВОВАТЬ'} <ArrowRightIcon className="w-3 h-3" />
                    </span>
                    <div className="flex -space-x-2">
                      {[1, 2, 3].map(i => (
                        <div key={i} className="w-7 h-7 bg-gray-100 dark:bg-gray-800 rounded-full border-2 border-[var(--tg-theme-secondary-bg-color)] flex items-center justify-center">
                          <UserGroupIcon className="w-3.5 h-3.5 text-gray-300" />
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}
    </div>
  );

  const renderReferralStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <button onClick={() => setStep(ContestStep.LIST)} className="mb-6 flex items-center gap-2 text-blue-600 font-black text-[10px] uppercase tracking-widest">
        <ChevronLeftIcon className="w-4 h-4" /> Назад
      </button>
      <div className="flex-1 flex flex-col justify-center items-center text-center space-y-8">
        <div className="relative">
          <div className="absolute inset-0 bg-blue-500/10 blur-[3rem] rounded-full"></div>
          <div className="relative w-28 h-28 bg-white dark:bg-gray-900 rounded-[2.5rem] flex items-center justify-center shadow-xl border border-blue-500/5">
            <LinkIcon className="w-14 h-14 text-blue-600" />
          </div>
        </div>
        <div className="space-y-3 px-4">
          <h1 className="text-2xl font-black leading-tight">{selectedContest?.title}</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-base font-medium leading-relaxed">
            Вы должны быть зарегистрированы по нашей ссылке Beef.
          </p>
        </div>

        <a 
          href={selectedContest?.referralLink} 
          target="_blank"
          className="w-full p-5 bg-gradient-to-br from-blue-600 to-blue-700 text-white rounded-[2rem] flex items-center justify-between shadow-xl shadow-blue-600/30 active:scale-[0.98] transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center">
              <LinkIcon className="w-7 h-7" />
            </div>
            <span className="font-black text-lg tracking-tight">РЕГИСТРАЦИЯ</span>
          </div>
          <ArrowRightIcon className="w-6 h-6 mr-1 opacity-50" />
        </a>

        {error && (
          <div className="flex items-center gap-3 p-4 bg-red-50 dark:bg-red-900/10 text-red-600 rounded-3xl text-xs animate-shake border border-red-100 dark:border-red-900/10">
            <ExclamationCircleIcon className="w-6 h-6 flex-shrink-0" />
            <p className="text-left leading-tight font-black">{error}</p>
          </div>
        )}
      </div>

      <button
        disabled={isChecking}
        onClick={handleReferralCheck}
        className="w-full py-5 rounded-[2rem] font-black text-xl btn-primary flex items-center justify-center gap-4 disabled:opacity-50 transition-all shadow-xl shadow-blue-600/20 active:scale-95 mb-4"
      >
        {isChecking ? <ClockIcon className="w-6 h-6 animate-spin" /> : 'ПРОВЕРИТЬ'}
      </button>
    </div>
  );

  const renderPayoutStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in">
      <div className="flex-1 space-y-8 pt-6">
        <div className="space-y-3">
          <h1 className="text-4xl font-black tracking-tighter">ВЫПЛАТА</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-snug font-medium opacity-70">
            Куда отправить деньги в случае победы?
          </p>
        </div>

        <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-[2rem] border border-gray-100 dark:border-gray-800 shadow-inner">
          <button 
            onClick={() => { setPayoutType('card'); setPayoutValue(''); }}
            className={`flex-1 py-4 rounded-[1.5rem] text-xs font-black transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-xl text-blue-600' : 'opacity-30'}`}
          >
            КАРТА (RUB)
          </button>
          <button 
            onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }}
            className={`flex-1 py-4 rounded-[1.5rem] text-xs font-black transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-xl text-green-600' : 'opacity-30'}`}
          >
            USDT (TRC20)
          </button>
        </div>

        <div className="space-y-4">
          <div className="relative">
            <div className="absolute left-6 top-1/2 -translate-y-1/2">
              {payoutType === 'card' ? <CreditCardIcon className="w-7 h-7 text-gray-300" /> : <CurrencyDollarIcon className="w-7 h-7 text-green-500" />}
            </div>
            <input 
              type="text"
              placeholder={payoutType === 'card' ? "Номер вашей карты" : "Адрес кошелька TRC20"}
              value={payoutValue}
              onChange={(e) => setPayoutValue(e.target.value)}
              className="w-full py-6 pl-16 pr-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2rem] font-mono text-xl border-2 border-transparent focus:border-blue-600 transition-all outline-none shadow-sm placeholder:opacity-20 text-[var(--tg-theme-text-color)]"
            />
          </div>
          <div className="px-6">
            <p className="text-[9px] text-blue-600 uppercase tracking-widest font-black opacity-50">
              {payoutType === 'card' ? "Укажите номер карты без пробелов" : "Только сеть TRON (TRC20)"}
            </p>
          </div>
        </div>
      </div>

      <button
        disabled={!validatePayout()}
        onClick={() => setStep(ContestStep.FINAL)}
        className="w-full py-6 rounded-[2rem] font-black text-xl btn-primary disabled:opacity-20 transition-all shadow-xl shadow-blue-600/30 active:scale-95 mb-6"
      >
        ПРОДОЛЖИТЬ
      </button>
    </div>
  );

  const renderFinalStep = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center">
      <div className="flex-1 flex flex-col justify-center space-y-10">
        <div className="relative w-32 h-32 mx-auto">
          <div className="absolute inset-0 bg-blue-600/20 rounded-[3rem] blur-[3rem]"></div>
          <div className="relative w-full h-full bg-white dark:bg-gray-900 rounded-[3rem] flex items-center justify-center border-2 border-blue-600/10 shadow-xl">
            <CheckBadgeIcon className="w-20 h-20 text-blue-600" />
          </div>
        </div>
        <div className="space-y-4 px-6">
          <h1 className="text-3xl font-black tracking-tighter uppercase leading-none">ПОЧТИ У ЦЕЛИ!</h1>
          <p className="text-[var(--tg-theme-hint-color)] text-lg leading-relaxed font-medium">
            Нажми «ВСТУПИТЬ», чтобы зафиксировать участие в розыгрыше <span className="text-blue-600 font-black">{selectedContest?.prizeRub?.toLocaleString()} ₽</span>
          </p>
        </div>
        <div className="p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] mx-2 border border-blue-600/5 shadow-inner">
          <p className="text-[9px] text-blue-600 uppercase tracking-widest font-black mb-2 opacity-40">ВАШИ РЕКВИЗИТЫ:</p>
          <p className="font-mono text-base break-all font-black text-[var(--tg-theme-text-color)]">{payoutValue}</p>
        </div>
      </div>

      <button
        disabled={isFinalizing}
        onClick={handleFinalParticipate}
        className="w-full py-7 rounded-[2.5rem] font-black text-2xl btn-primary shadow-2xl flex items-center justify-center gap-4 active:scale-95 transition-all mb-6"
      >
        {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin" /> : 'ВСТУПИТЬ В ИГРУ'}
      </button>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col h-full p-6 animate-fade-in text-center justify-center space-y-10">
      <div className="relative">
        <div className="absolute inset-0 bg-green-500/20 blur-[5rem] rounded-full animate-pulse"></div>
        <div className="relative w-40 h-40 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center mx-auto text-white shadow-2xl">
          <CheckBadgeIcon className="w-24 h-24 drop-shadow-xl" />
        </div>
      </div>
      <div className="space-y-4">
        <h1 className="text-4xl font-black tracking-tighter uppercase">УЧАСТВУЕШЬ!</h1>
        <p className="text-[var(--tg-theme-hint-color)] px-10 text-xl font-medium">
          Ты уже в списке претендентов. Жди результатов в канале. Удачи!
        </p>
      </div>
      <button 
        onClick={() => setStep(ContestStep.LIST)}
        className="mt-12 font-black text-blue-600 text-lg flex items-center justify-center gap-2 mx-auto active:scale-90"
      >
        <ChevronLeftIcon className="w-6 h-6" /> К СПИСКУ
      </button>
    </div>
  );

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] select-none overflow-hidden text-[var(--tg-theme-text-color)] font-sans">
      {view === 'admin' ? renderAdminPanel() : (
        <>
          {step === ContestStep.LIST && renderContestList()}
          {step === ContestStep.REFERRAL && renderReferralStep()}
          {step === ContestStep.PAYOUT && renderPayoutStep()}
          {step === ContestStep.FINAL && renderFinalStep()}
          {step === ContestStep.SUCCESS && renderSuccess()}
        </>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;700;800&display=swap');

        body {
          font-family: 'Plus Jakarta Sans', sans-serif;
        }

        @keyframes fade-in {
          from { opacity: 0; transform: scale(0.98) translateY(15px); }
          to { opacity: 1; transform: scale(1) translateY(0); }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-8px); }
          75% { transform: translateX(8px); }
        }
        .animate-fade-in { animation: fade-in 0.6s cubic-bezier(0.2, 1, 0.2, 1) forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out 0s 2; }

        .btn-primary {
          background: linear-gradient(135deg, #2481cc 0%, #1a65a3 100%);
          color: white !important;
        }

        input::placeholder {
          color: #999;
          opacity: 0.5;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

// ========================================================
// ПОДКЛЮЧЕНИЕ БАЗЫ ДАННЫХ (Vercel KV)
// Скопируй эти значения из панели Vercel (Storage -> Redis -> REST API)
// ========================================================
const KV_REST_API_URL = ''; // Вставь URL сюда
const KV_REST_API_TOKEN = ''; // Вставь TOKEN сюда
// ========================================================

const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);

  // States for flow
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin form
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    const api_url = KV_REST_API_URL || process.env.KV_REST_API_URL;
    const api_token = KV_REST_API_TOKEN || process.env.KV_REST_API_TOKEN;

    if (!api_url || !api_token) {
      console.warn("База данных не настроена. Используем временную память.");
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
      setIsLoading(false);
      return;
    }

    try {
      const res = await fetch(`${api_url}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${api_token}` }
      });
      const data = await res.json();
      if (data.result) {
        setContests(JSON.parse(data.result));
      }
    } catch (e) {
      console.error("Ошибка загрузки из базы:", e);
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    const api_url = KV_REST_API_URL || process.env.KV_REST_API_URL;
    const api_token = KV_REST_API_TOKEN || process.env.KV_REST_API_TOKEN;

    if (!api_url || !api_token) return;

    try {
      await fetch(`${api_url}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${api_token}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Ошибка сохранения в базу:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }
    fetchContests();
    const participations = localStorage.getItem(PARTICIPATION_KEY);
    if (participations) setParticipatedIds(JSON.parse(participations));

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => { if (data.rates?.USD) setUsdRate(data.rates.USD); });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);
    setNewTitle(''); setNewDesc(''); setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
  };

  const handleReferralCheck = () => {
    setIsChecking(true);
    setTimeout(() => {
      setIsChecking(false);
      if (checkAttempts < 1) {
        setCheckAttempts(prev => prev + 1);
        setError("Регистрация не подтверждена. Попробуй еще раз.");
      } else {
        setStep(ContestStep.PAYOUT);
      }
    }, 2500);
  };

  const handleFinalParticipate = () => {
    setIsFinalizing(true);
    setTimeout(() => {
      if (selectedContest) {
        const newPart = [...participatedIds, selectedContest.id];
        setParticipatedIds(newPart);
        localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(newPart));
      }
      setIsFinalizing(false);
      setStep(ContestStep.SUCCESS);
    }, 1500);
  };

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] overflow-hidden font-sans select-none">
      {/* Если ключи не введены и ты админ, покажем напоминание */}
      {isAdmin && !KV_REST_API_URL && !process.env.KV_REST_API_URL && (
        <div className="bg-orange-500 text-white text-[10px] p-2 text-center font-bold">
          БАЗА НЕ ПОДКЛЮЧЕНА: ВСТАВЬ КЛЮЧИ В APP.TSX
        </div>
      )}

      {view === 'admin' ? (
        <div className="p-6 h-full overflow-y-auto pb-24 space-y-8 animate-fade-in">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-black">Админка</h1>
            <button onClick={() => setView('user')} className="text-blue-500 font-bold">Выход</button>
          </div>

          <div className="bg-[var(--tg-theme-secondary-bg-color)] p-6 rounded-[2rem] space-y-4 border border-blue-500/10 shadow-xl">
            <input 
              placeholder="Название розыгрыша" 
              value={newTitle} 
              onChange={e => setNewTitle(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 rounded-2xl border border-gray-200 dark:border-gray-800 text-black dark:text-white font-bold"
            />
            <textarea 
              placeholder="Описание..." 
              value={newDesc} 
              onChange={e => setNewDesc(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 rounded-2xl border border-gray-200 dark:border-gray-800 h-20 text-black dark:text-white"
            />
            <input 
              type="number"
              placeholder="Приз в рублях (напр. 5000)" 
              value={newPrizeRub} 
              onChange={e => setNewPrizeRub(e.target.value)}
              className="w-full p-4 bg-white dark:bg-gray-950 rounded-2xl border border-gray-200 dark:border-gray-800 text-blue-600 font-black"
            />
            <button 
              onClick={createContest}
              disabled={!newTitle || !newPrizeRub}
              className="w-full py-5 bg-blue-600 text-white rounded-[1.5rem] font-black shadow-lg disabled:opacity-30"
            >
              ОПУБЛИКОВАТЬ В ОБЛАКО
            </button>
          </div>

          <div className="space-y-3">
            <h2 className="font-bold opacity-50 uppercase text-xs tracking-widest">Управление</h2>
            {contests.map(c => (
              <div key={c.id} className="p-4 bg-[var(--tg-theme-secondary-bg-color)] rounded-3xl flex justify-between items-center">
                <div>
                  <p className="font-black truncate w-40">{c.title}</p>
                  <p className="text-[10px] text-blue-500 font-bold">{c.prizeRub} RUB</p>
                </div>
                <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 rounded-2xl"><TrashIcon className="w-5 h-5"/></button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="h-full">
          {step === ContestStep.LIST && (
            <div className="p-6 space-y-8 animate-fade-in overflow-y-auto h-full">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white"><TrophyIcon className="w-6 h-6"/></div>
                  <h1 className="text-xl font-black">Beef Contest</h1>
                </div>
                {isAdmin && <button onClick={() => setView('admin')} className="p-2 bg-blue-50 rounded-xl"><ShieldCheckIcon className="w-6 h-6 text-blue-600"/></button>}
              </div>

              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-20 opacity-30 gap-4">
                  <ClockIcon className="w-10 h-10 animate-spin"/>
                  <p className="font-black text-xs uppercase tracking-widest">Загрузка...</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {contests.map(c => {
                    const joined = participatedIds.includes(c.id);
                    return (
                      <div key={c.id} onClick={() => { setSelectedContest(c); setStep(joined ? ContestStep.SUCCESS : ContestStep.REFERRAL); }} className="p-6 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] relative overflow-hidden active:scale-95 transition-all shadow-sm border border-transparent hover:border-blue-500/20">
                        {joined && <div className="absolute top-0 right-0 bg-green-500 text-white px-3 py-1 rounded-bl-xl text-[8px] font-black uppercase">Участвую</div>}
                        <h3 className="text-lg font-black mb-2">{c.title}</h3>
                        <div className="text-blue-600 font-black text-sm mb-4">{c.prizeRub?.toLocaleString()} ₽ / ${c.prizeUsd}</div>
                        <p className="text-xs opacity-50 line-clamp-2 mb-4">{c.description}</p>
                        <div className="flex items-center justify-between">
                          <span className="text-[9px] font-black text-blue-500 uppercase tracking-widest">Подробнее</span>
                          <ArrowRightIcon className="w-4 h-4 text-blue-500"/>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {step === ContestStep.REFERRAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-10 animate-fade-in">
              <div className="w-24 h-24 bg-blue-50 rounded-[2rem] flex items-center justify-center"><LinkIcon className="w-12 h-12 text-blue-600"/></div>
              <div className="space-y-4">
                <h1 className="text-3xl font-black">{selectedContest?.title}</h1>
                <p className="opacity-60 px-6 font-medium">Нужно быть зарегистрированным в Beef по нашей ссылке</p>
              </div>
              <a href={selectedContest?.referralLink} target="_blank" className="w-full p-5 bg-blue-600 text-white rounded-[2rem] font-black text-xl shadow-xl shadow-blue-600/30">РЕГИСТРАЦИЯ</a>
              {error && <p className="text-red-500 font-bold animate-shake text-sm">{error}</p>}
              <button onClick={handleReferralCheck} disabled={isChecking} className="w-full py-5 border-2 border-blue-600 text-blue-600 rounded-[2rem] font-black uppercase tracking-widest text-sm flex items-center justify-center gap-3">
                {isChecking ? <ClockIcon className="w-5 h-5 animate-spin"/> : "Проверить регистрацию"}
              </button>
            </div>
          )}

          {step === ContestStep.PAYOUT && (
            <div className="p-6 h-full flex flex-col animate-fade-in">
              <div className="flex-1 space-y-10 pt-10">
                <h1 className="text-4xl font-black">КУДА ВЫПЛАТИТЬ?</h1>
                <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-1.5 rounded-[2rem]">
                  <button onClick={() => setPayoutType('card')} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'card' ? 'bg-white shadow-lg text-blue-600' : 'opacity-40'}`}>КАРТА</button>
                  <button onClick={() => setPayoutType('trc20')} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'trc20' ? 'bg-white shadow-lg text-green-600' : 'opacity-40'}`}>USDT</button>
                </div>
                <input 
                  placeholder={payoutType === 'card' ? "Номер карты" : "Адрес кошелька TRC20"}
                  value={payoutValue}
                  onChange={e => setPayoutValue(e.target.value)}
                  className="w-full py-6 px-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2rem] text-xl font-mono focus:border-blue-600 border-2 border-transparent transition-all outline-none"
                />
              </div>
              <button onClick={() => setStep(ContestStep.FINAL)} disabled={payoutValue.length < 5} className="w-full py-6 bg-blue-600 text-white rounded-[2rem] font-black text-2xl shadow-2xl disabled:opacity-20">ПРОДОЛЖИТЬ</button>
            </div>
          )}

          {step === ContestStep.FINAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-32 h-32 bg-green-50 rounded-[3rem] flex items-center justify-center border-2 border-green-500/10 shadow-inner"><CheckBadgeIcon className="w-16 h-16 text-green-600"/></div>
              <div className="space-y-4">
                <h1 className="text-4xl font-black uppercase">ФИНАЛ</h1>
                <p className="opacity-50 text-lg">Жми кнопку ниже, чтобы войти в список участников</p>
              </div>
              <button onClick={handleFinalParticipate} disabled={isFinalizing} className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl flex items-center justify-center gap-4">
                {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin"/> : "ВСТУПИТЬ"}
              </button>
            </div>
          )}

          {step === ContestStep.SUCCESS && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-10 animate-fade-in">
              <div className="w-40 h-40 bg-green-500 rounded-full flex items-center justify-center text-white shadow-2xl animate-bounce"><CheckBadgeIcon className="w-24 h-24"/></div>
              <h1 className="text-4xl font-black">УСПЕХ!</h1>
              <p className="opacity-60 text-xl px-10">Твоя заявка принята. Жди результатов в канале!</p>
              <button onClick={() => setStep(ContestStep.LIST)} className="text-blue-600 font-black uppercase tracking-widest flex items-center gap-2"><ChevronLeftIcon className="w-5 h-5"/> К списку</button>
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-5px); } 75% { transform: translateX(5px); } }
        .animate-fade-in { animation: fade-in 0.5s ease-out forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

// ========================================================
// 🛠 НАСТРОЙКИ БАЗЫ ДАННЫХ (Vercel KV REST API)
// 1. Зайди в Vercel -> Storage -> Твоя база
// 2. Найди раздел "REST API"
// 3. Скопируй URL и TOKEN и вставь в кавычки ниже:
// ========================================================
const KV_REST_API_URL = ''; 
const KV_REST_API_TOKEN = ''; 
// ========================================================

const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);

  // States
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin form
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    // Пробуем взять из кода или из переменных окружения Vercel
    const api_url = KV_REST_API_URL || (typeof process !== 'undefined' ? process.env.KV_REST_API_URL : '');
    const api_token = KV_REST_API_TOKEN || (typeof process !== 'undefined' ? process.env.KV_REST_API_TOKEN : '');

    if (!api_url || !api_token) {
      console.warn("База не настроена. Данные будут пропадать.");
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
      setIsLoading(false);
      return;
    }

    try {
      const res = await fetch(`${api_url}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${api_token}` }
      });
      const data = await res.json();
      if (data.result) {
        setContests(JSON.parse(data.result));
      }
    } catch (e) {
      console.error("DB Error:", e);
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    const api_url = KV_REST_API_URL || (typeof process !== 'undefined' ? process.env.KV_REST_API_URL : '');
    const api_token = KV_REST_API_TOKEN || (typeof process !== 'undefined' ? process.env.KV_REST_API_TOKEN : '');

    if (!api_url || !api_token) return;

    try {
      await fetch(`${api_url}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${api_token}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Save Error:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }
    fetchContests();
    const p = localStorage.getItem(PARTICIPATION_KEY);
    if (p) setParticipatedIds(JSON.parse(p));

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => { if (data.rates?.USD) setUsdRate(data.rates.USD); });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);
    setNewTitle(''); setNewDesc(''); setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
  };

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] overflow-hidden font-sans select-none">
      {/* Только админ видит предупреждение о базе */}
      {isAdmin && !KV_REST_API_URL && (
        <div className="bg-red-600 text-white text-[10px] py-1 px-4 text-center font-black animate-pulse uppercase">
          Внимание: База не подключена! Вставь REST URL и TOKEN в App.tsx
        </div>
      )}

      {view === 'admin' ? (
        <div className="p-6 h-full overflow-y-auto pb-24 space-y-8 animate-fade-in bg-white dark:bg-black">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-black text-black dark:text-white">Админ-панель</h1>
            <button onClick={() => setView('user')} className="text-blue-600 font-bold p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">К юзерам</button>
          </div>

          <div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-[2.5rem] space-y-4 border border-gray-200 dark:border-gray-800 shadow-xl">
            <div className="space-y-1">
               <label className="text-[10px] font-black uppercase opacity-40 px-2">Заголовок</label>
               <input 
                placeholder="Зимний розыгрыш" 
                value={newTitle} 
                onChange={e => setNewTitle(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-black dark:text-white font-bold text-lg"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black uppercase opacity-40 px-2">Описание</label>
              <textarea 
                placeholder="Условия участия..." 
                value={newDesc} 
                onChange={e => setNewDesc(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 h-24 text-black dark:text-white"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase opacity-40 px-2">Приз RUB</label>
                <input 
                  type="number"
                  placeholder="5000" 
                  value={newPrizeRub} 
                  onChange={e => setNewPrizeRub(e.target.value)}
                  className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-blue-600 font-black text-xl"
                />
              </div>
              <div className="space-y-1 opacity-50">
                <label className="text-[10px] font-black uppercase px-2">Приз USD</label>
                <div className="w-full p-4 bg-gray-100 dark:bg-gray-950 rounded-2xl font-black text-xl">
                  ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
                </div>
              </div>
            </div>
            <button 
              onClick={createContest}
              disabled={!newTitle || !newPrizeRub}
              className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-blue-600/30 active:scale-95 transition-all disabled:opacity-20"
            >
              ОПУБЛИКОВАТЬ В БАЗУ
            </button>
          </div>

          <div className="space-y-4">
            <h2 className="font-black text-xs uppercase tracking-widest opacity-30 px-2">Живые конкурсы</h2>
            {contests.length === 0 && <p className="text-center py-10 opacity-20 italic">Пока пусто...</p>}
            {contests.map(c => (
              <div key={c.id} className="p-5 bg-gray-50 dark:bg-gray-900 rounded-[2rem] flex justify-between items-center border border-gray-100 dark:border-gray-800">
                <div className="overflow-hidden mr-4">
                  <p className="font-black text-black dark:text-white truncate">{c.title}</p>
                  <p className="text-xs text-blue-600 font-bold">{c.prizeRub} ₽</p>
                </div>
                <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl active:scale-90"><TrashIcon className="w-6 h-6"/></button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="h-full">
          {step === ContestStep.LIST && (
            <div className="p-6 space-y-8 animate-fade-in overflow-y-auto h-full pb-20">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-lg shadow-blue-600/20"><TrophyIcon className="w-7 h-7"/></div>
                  <div>
                    <h1 className="text-xl font-black leading-none">Beef Contest</h1>
                    <p className="text-[9px] uppercase font-black text-blue-500 tracking-wider mt-1">Только для своих</p>
                  </div>
                </div>
                {isAdmin && <button onClick={() => setView('admin')} className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl"><ShieldCheckIcon className="w-7 h-7 text-blue-600"/></button>}
              </div>

              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-32 opacity-20 gap-4">
                  <ClockIcon className="w-12 h-12 animate-spin"/>
                  <p className="font-black text-[10px] uppercase tracking-[0.3em]">Синхронизация...</p>
                </div>
              ) : (
                <div className="space-y-5">
                  {contests.length === 0 ? (
                    <div className="text-center py-20 opacity-20 italic font-medium">Новых розыгрышей пока нет. Заходи позже!</div>
                  ) : (
                    contests.map(c => {
                      const joined = participatedIds.includes(c.id);
                      return (
                        <div key={c.id} onClick={() => { setSelectedContest(c); setStep(joined ? ContestStep.SUCCESS : ContestStep.REFERRAL); }} className={`p-7 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] relative overflow-hidden active:scale-[0.97] transition-all shadow-sm border-2 ${joined ? 'border-green-500/20' : 'border-transparent'}`}>
                          {joined && (
                            <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase flex items-center gap-1 shadow-lg">
                              <CheckBadgeIcon className="w-3.5 h-3.5"/> В игре
                            </div>
                          )}
                          <h3 className="text-xl font-black mb-2 pr-10">{c.title}</h3>
                          <div className="flex items-center gap-2 mb-4">
                            <BanknotesIcon className="w-5 h-5 text-blue-600 opacity-50"/>
                            <span className="text-blue-600 font-black text-lg">{c.prizeRub?.toLocaleString()} ₽ <span className="text-xs opacity-30 font-bold">/ ${c.prizeUsd}</span></span>
                          </div>
                          <p className="text-xs opacity-50 line-clamp-2 mb-6 font-medium leading-relaxed">{c.description}</p>
                          <div className="flex items-center justify-between pt-2 border-t border-gray-100 dark:border-gray-800">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{joined ? 'Уже участвую' : 'Участвовать'}</span>
                            <ArrowRightIcon className="w-5 h-5 text-blue-500"/>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              )}
            </div>
          )}

          {step === ContestStep.REFERRAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-28 h-28 bg-blue-50 dark:bg-blue-900/10 rounded-[2.5rem] flex items-center justify-center shadow-inner"><LinkIcon className="w-14 h-14 text-blue-600"/></div>
              <div className="space-y-4 px-4">
                <h1 className="text-3xl font-black tracking-tight">{selectedContest?.title}</h1>
                <p className="opacity-60 text-lg font-medium leading-relaxed">Вы должны быть зарегистрированы в Beef по нашей ссылке, чтобы претендовать на приз.</p>
              </div>
              <div className="w-full space-y-4">
                <a href={selectedContest?.referralLink} target="_blank" className="w-full p-6 bg-blue-600 text-white rounded-[2rem] font-black text-xl shadow-xl shadow-blue-600/30 flex items-center justify-center gap-3 active:scale-95 transition-all">
                  РЕГИСТРАЦИЯ <ArrowRightIcon className="w-6 h-6"/>
                </a>
                <button onClick={() => { setIsChecking(true); setTimeout(() => { setIsChecking(false); setCheckAttempts(a => a + 1); if(checkAttempts >= 1) setStep(ContestStep.PAYOUT); else setError("Регистрация не найдена. Попробуй еще раз через минуту."); }, 2000); }} disabled={isChecking} className="w-full py-5 border-2 border-blue-600 text-blue-600 rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 active:bg-blue-50 transition-all">
                  {isChecking ? <ClockIcon className="w-6 h-6 animate-spin"/> : "Проверить регистрацию"}
                </button>
              </div>
              {error && <p className="text-red-500 font-bold animate-shake text-sm px-6 leading-tight">{error}</p>}
              <button onClick={() => setStep(ContestStep.LIST)} className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">Назад к списку</button>
            </div>
          )}

          {step === ContestStep.PAYOUT && (
            <div className="p-8 h-full flex flex-col animate-fade-in">
              <div className="flex-1 space-y-12 pt-10">
                <div className="space-y-4">
                  <h1 className="text-5xl font-black tracking-tighter">ВЫПЛАТА</h1>
                  <p className="opacity-50 text-xl font-medium">Куда отправить деньги?</p>
                </div>
                <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-[2rem] border border-gray-100 dark:border-gray-800">
                  <button onClick={() => { setPayoutType('card'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-xl text-blue-600' : 'opacity-40'}`}>БАНК. КАРТА</button>
                  <button onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-xl text-green-600' : 'opacity-40'}`}>USDT TRC20</button>
                </div>
                <div className="relative">
                  <div className="absolute left-6 top-1/2 -translate-y-1/2 opacity-20">
                    {payoutType === 'card' ? <CreditCardIcon className="w-8 h-8"/> : <CurrencyDollarIcon className="w-8 h-8"/>}
                  </div>
                  <input 
                    placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька..."}
                    value={payoutValue}
                    onChange={e => setPayoutValue(e.target.value)}
                    className="w-full py-7 pl-16 pr-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] text-2xl font-mono focus:border-blue-600 border-2 border-transparent transition-all outline-none shadow-sm"
                  />
                </div>
              </div>
              <button onClick={() => setStep(ContestStep.FINAL)} disabled={payoutValue.length < 8} className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl disabled:opacity-20 active:scale-95 transition-all mb-4">ПРОДОЛЖИТЬ</button>
            </div>
          )}

          {step === ContestStep.FINAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-32 h-32 bg-green-50 dark:bg-green-900/10 rounded-[3rem] flex items-center justify-center border-2 border-green-500/10 shadow-xl"><CheckBadgeIcon className="w-20 h-20 text-green-500"/></div>
              <div className="space-y-4 px-6">
                <h1 className="text-4xl font-black uppercase tracking-tight">ПОДТВЕРЖДЕНИЕ</h1>
                <p className="opacity-50 text-xl font-medium">Вы в шаге от участия. Нажмите кнопку, чтобы зафиксировать заявку.</p>
              </div>
              <div className="w-full p-6 bg-gray-50 dark:bg-gray-900 rounded-[2rem] border border-gray-100 dark:border-gray-800 shadow-inner">
                 <p className="text-[10px] font-black uppercase opacity-30 mb-2">Ваши реквизиты</p>
                 <p className="font-mono text-lg font-black break-all">{payoutValue}</p>
              </div>
              <button onClick={() => { setIsFinalizing(true); setTimeout(() => { if(selectedContest) { const n = [...participatedIds, selectedContest.id]; setParticipatedIds(n); localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(n)); } setIsFinalizing(false); setStep(ContestStep.SUCCESS); }, 1500); }} disabled={isFinalizing} className="w-full py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl flex items-center justify-center gap-4 active:scale-95 transition-all">
                {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin"/> : "ВСТУПИТЬ В ИГРУ"}
              </button>
            </div>
          )}

          {step === ContestStep.SUCCESS && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="relative">
                <div className="absolute inset-0 bg-green-500/20 blur-[4rem] rounded-full animate-pulse"></div>
                <div className="relative w-44 h-44 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center text-white shadow-2xl"><CheckBadgeIcon className="w-28 h-28"/></div>
              </div>
              <div className="space-y-4">
                <h1 className="text-4xl font-black uppercase tracking-tighter">ВСЁ ГОТОВО!</h1>
                <p className="opacity-60 text-xl px-10 font-medium">Ваша заявка принята. Теперь просто ждите результатов в канале. Удачи!</p>
              </div>
              <button onClick={() => setStep(ContestStep.LIST)} className="text-blue-600 font-black uppercase tracking-widest text-sm flex items-center gap-2 py-4 px-8 bg-blue-50 dark:bg-blue-900/10 rounded-2xl active:scale-90 transition-all"><ChevronLeftIcon className="w-6 h-6"/> К СПИСКУ</button>
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(15px) scale(0.98); } to { opacity: 1; transform: translateY(0) scale(1); } }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-6px); } 75% { transform: translateX(6px); } }
        .animate-fade-in { animation: fade-in 0.6s cubic-bezier(0.2, 1, 0.2, 1) forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon
} from '@heroicons/react/24/outline';

// ========================================================
// 🛠 ПОДКЛЮЧЕНИЕ БАЗЫ (ТВОЯ ЗАДАЧА ТУТ)
// 1. В Vercel Storage нажми на созданную базу Upstash.
// 2. Листай вниз до раздела "REST API".
// 3. Выбери вкладку ".env" (там удобнее всего копировать).
// 4. Скопируй значения и вставь в кавычки ниже:
// ========================================================
const KV_REST_API_URL = ''; 
const KV_REST_API_TOKEN = ''; 
// ========================================================

const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);

  // States
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin form
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    const api_url = KV_REST_API_URL || (typeof process !== 'undefined' ? process.env.KV_REST_API_URL : '');
    const api_token = KV_REST_API_TOKEN || (typeof process !== 'undefined' ? process.env.KV_REST_API_TOKEN : '');

    if (!api_url || !api_token) {
      console.warn("API ключи не найдены. Работаем в демо-режиме (данные не сохранятся)");
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
      setIsLoading(false);
      return;
    }

    try {
      const res = await fetch(`${api_url}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${api_token}` }
      });
      const data = await res.json();
      if (data.result) {
        setContests(JSON.parse(data.result));
      }
    } catch (e) {
      console.error("Database fetch failed:", e);
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    const api_url = KV_REST_API_URL || (typeof process !== 'undefined' ? process.env.KV_REST_API_URL : '');
    const api_token = KV_REST_API_TOKEN || (typeof process !== 'undefined' ? process.env.KV_REST_API_TOKEN : '');

    if (!api_url || !api_token) return;

    try {
      await fetch(`${api_url}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${api_token}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Database save failed:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }
    fetchContests();
    const p = localStorage.getItem(PARTICIPATION_KEY);
    if (p) setParticipatedIds(JSON.parse(p));

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => { if (data.rates?.USD) setUsdRate(data.rates.USD); });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);
    setNewTitle(''); setNewDesc(''); setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
  };

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] overflow-hidden font-sans select-none">
      {isAdmin && !KV_REST_API_URL && (
        <div className="bg-red-600 text-white text-[10px] py-1 px-4 text-center font-black animate-pulse uppercase sticky top-0 z-50">
          ⚠️ БД НЕ ПОДКЛЮЧЕНА! ВСТАВЬ КЛЮЧИ В APP.TSX
        </div>
      )}

      {view === 'admin' ? (
        <div className="p-6 h-full overflow-y-auto pb-24 space-y-8 animate-fade-in bg-white dark:bg-black">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-black text-black dark:text-white">Админ-панель</h1>
            <button onClick={() => setView('user')} className="text-blue-600 font-bold p-2 bg-blue-50 dark:bg-blue-900/20 rounded-xl">К юзерам</button>
          </div>

          <div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-[2.5rem] space-y-4 border border-gray-200 dark:border-gray-800 shadow-xl">
            <div className="space-y-1">
               <label className="text-[10px] font-black uppercase opacity-40 px-2">Заголовок</label>
               <input 
                placeholder="Зимний розыгрыш" 
                value={newTitle} 
                onChange={e => setNewTitle(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-black dark:text-white font-bold text-lg"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black uppercase opacity-40 px-2">Описание</label>
              <textarea 
                placeholder="Условия участия..." 
                value={newDesc} 
                onChange={e => setNewDesc(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 h-24 text-black dark:text-white"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase opacity-40 px-2">Приз RUB</label>
                <input 
                  type="number"
                  placeholder="5000" 
                  value={newPrizeRub} 
                  onChange={e => setNewPrizeRub(e.target.value)}
                  className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-blue-600 font-black text-xl"
                />
              </div>
              <div className="space-y-1 opacity-50">
                <label className="text-[10px] font-black uppercase px-2">Приз USD</label>
                <div className="w-full p-4 bg-gray-100 dark:bg-gray-950 rounded-2xl font-black text-xl">
                  ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
                </div>
              </div>
            </div>
            <button 
              onClick={createContest}
              disabled={!newTitle || !newPrizeRub}
              className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-blue-600/30 active:scale-95 transition-all disabled:opacity-20"
            >
              ОПУБЛИКОВАТЬ В БАЗУ
            </button>
          </div>

          <div className="space-y-4">
            <h2 className="font-black text-xs uppercase tracking-widest opacity-30 px-2">Живые конкурсы</h2>
            {contests.length === 0 && <p className="text-center py-10 opacity-20 italic">Пока пусто...</p>}
            {contests.map(c => (
              <div key={c.id} className="p-5 bg-gray-50 dark:bg-gray-900 rounded-[2rem] flex justify-between items-center border border-gray-100 dark:border-gray-800">
                <div className="overflow-hidden mr-4">
                  <p className="font-black text-black dark:text-white truncate">{c.title}</p>
                  <p className="text-xs text-blue-600 font-bold">{c.prizeRub} ₽</p>
                </div>
                <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl active:scale-90"><TrashIcon className="w-6 h-6"/></button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="h-full">
          {step === ContestStep.LIST && (
            <div className="p-6 space-y-8 animate-fade-in overflow-y-auto h-full pb-20">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-lg shadow-blue-600/20"><TrophyIcon className="w-7 h-7"/></div>
                  <div>
                    <h1 className="text-xl font-black leading-none">Beef Contest</h1>
                    <p className="text-[9px] uppercase font-black text-blue-500 tracking-wider mt-1">Только для своих</p>
                  </div>
                </div>
                {isAdmin && <button onClick={() => setView('admin')} className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl"><ShieldCheckIcon className="w-7 h-7 text-blue-600"/></button>}
              </div>

              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-32 opacity-20 gap-4">
                  <ClockIcon className="w-12 h-12 animate-spin"/>
                  <p className="font-black text-[10px] uppercase tracking-[0.3em]">Синхронизация...</p>
                </div>
              ) : (
                <div className="space-y-5">
                  {contests.length === 0 ? (
                    <div className="text-center py-20 opacity-20 italic font-medium">Новых розыгрышей пока нет. Заходи позже!</div>
                  ) : (
                    contests.map(c => {
                      const joined = participatedIds.includes(c.id);
                      return (
                        <div key={c.id} onClick={() => { setSelectedContest(c); setStep(joined ? ContestStep.SUCCESS : ContestStep.REFERRAL); }} className={`p-7 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] relative overflow-hidden active:scale-[0.97] transition-all shadow-sm border-2 ${joined ? 'border-green-500/20' : 'border-transparent'}`}>
                          {joined && (
                            <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase flex items-center gap-1 shadow-lg">
                              <CheckBadgeIcon className="w-3.5 h-3.5"/> В игре
                            </div>
                          )}
                          <h3 className="text-xl font-black mb-2 pr-10">{c.title}</h3>
                          <div className="flex items-center gap-2 mb-4">
                            <BanknotesIcon className="w-5 h-5 text-blue-600 opacity-50"/>
                            <span className="text-blue-600 font-black text-lg">{c.prizeRub?.toLocaleString()} ₽ <span className="text-xs opacity-30 font-bold">/ ${c.prizeUsd}</span></span>
                          </div>
                          <p className="text-xs opacity-50 line-clamp-2 mb-6 font-medium leading-relaxed">{c.description}</p>
                          <div className="flex items-center justify-between pt-2 border-t border-gray-100 dark:border-gray-800">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{joined ? 'Уже участвую' : 'Участвовать'}</span>
                            <ArrowRightIcon className="w-5 h-5 text-blue-500"/>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              )}
            </div>
          )}

          {step === ContestStep.REFERRAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-28 h-28 bg-blue-50 dark:bg-blue-900/10 rounded-[2.5rem] flex items-center justify-center shadow-inner"><LinkIcon className="w-14 h-14 text-blue-600"/></div>
              <div className="space-y-4 px-4">
                <h1 className="text-3xl font-black tracking-tight">{selectedContest?.title}</h1>
                <p className="opacity-60 text-lg font-medium leading-relaxed">Вы должны быть зарегистрированы в Beef по нашей ссылке, чтобы претендовать на приз.</p>
              </div>
              <div className="w-full space-y-4">
                <a href={selectedContest?.referralLink} target="_blank" className="w-full p-6 bg-blue-600 text-white rounded-[2rem] font-black text-xl shadow-xl shadow-blue-600/30 flex items-center justify-center gap-3 active:scale-95 transition-all">
                  РЕГИСТРАЦИЯ <ArrowRightIcon className="w-6 h-6"/>
                </a>
                <button onClick={() => { setIsChecking(true); setTimeout(() => { setIsChecking(false); setCheckAttempts(a => a + 1); if(checkAttempts >= 1) setStep(ContestStep.PAYOUT); else setError("Регистрация не найдена. Попробуй еще раз через минуту."); }, 2000); }} disabled={isChecking} className="w-full py-5 border-2 border-blue-600 text-blue-600 rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 active:bg-blue-50 transition-all">
                  {isChecking ? <ClockIcon className="w-6 h-6 animate-spin"/> : "Проверить регистрацию"}
                </button>
              </div>
              {error && <p className="text-red-500 font-bold animate-shake text-sm px-6 leading-tight">{error}</p>}
              <button onClick={() => setStep(ContestStep.LIST)} className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">Назад к списку</button>
            </div>
          )}

          {step === ContestStep.PAYOUT && (
            <div className="p-8 h-full flex flex-col animate-fade-in">
              <div className="flex-1 space-y-12 pt-10">
                <div className="space-y-4">
                  <h1 className="text-5xl font-black tracking-tighter">ВЫПЛАТА</h1>
                  <p className="opacity-50 text-xl font-medium">Куда отправить деньги?</p>
                </div>
                <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-[2rem] border border-gray-100 dark:border-gray-800">
                  <button onClick={() => { setPayoutType('card'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-xl text-blue-600' : 'opacity-40'}`}>БАНК. КАРТА</button>
                  <button onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.5rem] font-black text-xs transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-xl text-green-600' : 'opacity-40'}`}>USDT TRC20</button>
                </div>
                <div className="relative">
                  <div className="absolute left-6 top-1/2 -translate-y-1/2 opacity-20">
                    {payoutType === 'card' ? <CreditCardIcon className="w-8 h-8"/> : <CurrencyDollarIcon className="w-8 h-8"/>}
                  </div>
                  <input 
                    placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька..."}
                    value={payoutValue}
                    onChange={e => setPayoutValue(e.target.value)}
                    className="w-full py-7 pl-16 pr-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] text-2xl font-mono focus:border-blue-600 border-2 border-transparent transition-all outline-none shadow-sm"
                  />
                </div>
              </div>
              <button onClick={() => setStep(ContestStep.FINAL)} disabled={payoutValue.length < 8} className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl disabled:opacity-20 active:scale-95 transition-all mb-4">ПРОДОЛЖИТЬ</button>
            </div>
          )}

          {step === ContestStep.FINAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-32 h-32 bg-green-50 dark:bg-green-900/10 rounded-[3rem] flex items-center justify-center border-2 border-green-500/10 shadow-xl"><CheckBadgeIcon className="w-20 h-20 text-green-500"/></div>
              <div className="space-y-4 px-6">
                <h1 className="text-4xl font-black uppercase tracking-tight">ПОДТВЕРЖДЕНИЕ</h1>
                <p className="opacity-50 text-xl font-medium">Вы в шаге от участия. Нажмите кнопку, чтобы зафиксировать заявку.</p>
              </div>
              <div className="w-full p-6 bg-gray-50 dark:bg-gray-900 rounded-[2rem] border border-gray-100 dark:border-gray-800 shadow-inner">
                 <p className="text-[10px] font-black uppercase opacity-30 mb-2">Ваши реквизиты</p>
                 <p className="font-mono text-lg font-black break-all">{payoutValue}</p>
              </div>
              <button onClick={() => { setIsFinalizing(true); setTimeout(() => { if(selectedContest) { const n = [...participatedIds, selectedContest.id]; setParticipatedIds(n); localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(n)); } setIsFinalizing(false); setStep(ContestStep.SUCCESS); }, 1500); }} disabled={isFinalizing} className="w-full py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl flex items-center justify-center gap-4 active:scale-95 transition-all">
                {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin"/> : "ВСТУПИТЬ В ИГРУ"}
              </button>
            </div>
          )}

          {step === ContestStep.SUCCESS && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="relative">
                <div className="absolute inset-0 bg-green-500/20 blur-[4rem] rounded-full animate-pulse"></div>
                <div className="relative w-44 h-44 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center text-white shadow-2xl"><CheckBadgeIcon className="w-28 h-28"/></div>
              </div>
              <div className="space-y-4">
                <h1 className="text-4xl font-black uppercase tracking-tighter">ВСЁ ГОТОВО!</h1>
                <p className="opacity-60 text-xl px-10 font-medium">Ваша заявка принята. Теперь просто ждите результатов в канале. Удачи!</p>
              </div>
              <button onClick={() => setStep(ContestStep.LIST)} className="text-blue-600 font-black uppercase tracking-widest text-sm flex items-center gap-2 py-4 px-8 bg-blue-50 dark:bg-blue-900/10 rounded-2xl active:scale-90 transition-all"><ChevronLeftIcon className="w-6 h-6"/> К СПИСКУ</button>
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(15px) scale(0.98); } to { opacity: 1; transform: translateY(0) scale(1); } }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-6px); } 75% { transform: translateX(6px); } }
        .animate-fade-in { animation: fade-in 0.6s cubic-bezier(0.2, 1, 0.2, 1) forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ExclamationCircleIcon,
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  PlusIcon,
  TrashIcon,
  UserGroupIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon,
  SignalIcon
} from '@heroicons/react/24/outline';

// ========================================================
// 🛠 ТЕБЕ НУЖНО ВСТАВИТЬ ДАННЫЕ СЮДА:
// Возьми их из вкладки "REST API" (раздел .env) в Vercel
// ========================================================
const KV_REST_API_URL = ''; 
const KV_REST_API_TOKEN = ''; 
// ========================================================

const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'none'>('none');

  // States
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin form
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    const api_url = KV_REST_API_URL;
    const api_token = KV_REST_API_TOKEN;

    if (!api_url || !api_token) {
      setDbStatus('none');
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
      setIsLoading(false);
      return;
    }

    try {
      const res = await fetch(`${api_url}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${api_token}` }
      });
      const data = await res.json();
      if (data.result) {
        setContests(JSON.parse(data.result));
      }
      setDbStatus('connected');
    } catch (e) {
      console.error("DB Error:", e);
      setDbStatus('error');
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    const api_url = KV_REST_API_URL;
    const api_token = KV_REST_API_TOKEN;

    if (!api_url || !api_token) return;

    try {
      await fetch(`${api_url}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${api_token}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("Save Error:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }
    fetchContests();
    const p = localStorage.getItem(PARTICIPATION_KEY);
    if (p) setParticipatedIds(JSON.parse(p));

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => { if (data.rates?.USD) setUsdRate(data.rates.USD); });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);
    setNewTitle(''); setNewDesc(''); setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
  };

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] overflow-hidden font-sans select-none">
      {isAdmin && dbStatus === 'none' && (
        <div className="bg-red-600 text-white text-[10px] py-1 px-4 text-center font-black animate-pulse uppercase sticky top-0 z-50 shadow-lg">
          ⚠️ БД НЕ ПОДКЛЮЧЕНА! ВСТАВЬ КЛЮЧИ В APP.TSX
        </div>
      )}

      {view === 'admin' ? (
        <div className="p-6 h-full overflow-y-auto pb-24 space-y-8 animate-fade-in bg-white dark:bg-black">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-black text-black dark:text-white leading-none">Админ-панель</h1>
              <div className="flex items-center gap-1.5 mt-2">
                <div className={`w-2 h-2 rounded-full ${dbStatus === 'connected' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500'}`}></div>
                <span className={`text-[10px] font-bold uppercase tracking-wider ${dbStatus === 'connected' ? 'text-green-600' : 'text-red-600'}`}>
                  {dbStatus === 'connected' ? 'База онлайн' : 'База оффлайн'}
                </span>
              </div>
            </div>
            <button onClick={() => setView('user')} className="text-blue-600 font-black p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl active:scale-95 transition-all text-xs uppercase tracking-widest">Выход</button>
          </div>

          <div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-[2.5rem] space-y-4 border border-gray-200 dark:border-gray-800 shadow-xl">
            <div className="space-y-1">
               <label className="text-[10px] font-black uppercase opacity-40 px-2">Название</label>
               <input 
                placeholder="Напр: Конкурс для трейдеров" 
                value={newTitle} 
                onChange={e => setNewTitle(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-black dark:text-white font-bold text-lg"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black uppercase opacity-40 px-2">Условия</label>
              <textarea 
                placeholder="Опиши условия коротко..." 
                value={newDesc} 
                onChange={e => setNewDesc(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 h-24 text-black dark:text-white"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase opacity-40 px-2">Приз RUB</label>
                <input 
                  type="number"
                  placeholder="5000" 
                  value={newPrizeRub} 
                  onChange={e => setNewPrizeRub(e.target.value)}
                  className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-blue-600 font-black text-xl"
                />
              </div>
              <div className="space-y-1 opacity-50">
                <label className="text-[10px] font-black uppercase px-2">Конвертация</label>
                <div className="w-full p-4 bg-gray-100 dark:bg-gray-950 rounded-2xl font-black text-xl">
                  ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
                </div>
              </div>
            </div>
            <button 
              onClick={createContest}
              disabled={!newTitle || !newPrizeRub}
              className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-blue-600/30 active:scale-95 transition-all disabled:opacity-20"
            >
              СОЗДАТЬ КОНКУРС
            </button>
          </div>

          <div className="space-y-4 pb-10">
            <h2 className="font-black text-[10px] uppercase tracking-widest opacity-30 px-2">Список активных конкурсов</h2>
            {contests.length === 0 && <div className="text-center py-10 opacity-20 italic">Конкурсов пока нет</div>}
            {contests.map(c => (
              <div key={c.id} className="p-5 bg-gray-50 dark:bg-gray-900 rounded-[2rem] flex justify-between items-center border border-gray-100 dark:border-gray-800 shadow-sm transition-all hover:bg-gray-100 dark:hover:bg-gray-800">
                <div className="overflow-hidden mr-4">
                  <p className="font-black text-black dark:text-white truncate text-base">{c.title}</p>
                  <p className="text-xs text-blue-600 font-bold">{c.prizeRub.toLocaleString()} ₽</p>
                </div>
                <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl active:scale-90 transition-all shadow-sm">
                  <TrashIcon className="w-6 h-6"/>
                </button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="h-full">
          {step === ContestStep.LIST && (
            <div className="p-6 space-y-8 animate-fade-in overflow-y-auto h-full pb-24">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-xl shadow-blue-600/20"><TrophyIcon className="w-7 h-7"/></div>
                  <div>
                    <h1 className="text-xl font-black leading-none">Beef Contest</h1>
                    <p className="text-[10px] uppercase font-black text-blue-500 tracking-wider mt-1">Твой шанс на успех</p>
                  </div>
                </div>
                {isAdmin && (
                  <button onClick={() => setView('admin')} className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl relative group">
                    <ShieldCheckIcon className="w-7 h-7 text-blue-600"/>
                    <div className={`absolute -top-1 -right-1 w-3 h-3 rounded-full border-2 border-white dark:border-black ${dbStatus === 'connected' ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  </button>
                )}
              </div>

              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-32 opacity-20 gap-4">
                  <ClockIcon className="w-12 h-12 animate-spin"/>
                  <p className="font-black text-[10px] uppercase tracking-[0.4em]">Синхронизация...</p>
                </div>
              ) : (
                <div className="space-y-5">
                  {contests.length === 0 ? (
                    <div className="text-center py-20 px-10">
                      <div className="w-20 h-20 bg-gray-100 dark:bg-gray-900 rounded-full flex items-center justify-center mx-auto mb-6 opacity-30">
                        <SignalIcon className="w-10 h-10"/>
                      </div>
                      <p className="opacity-30 italic font-medium">Новых розыгрышей пока нет. Заходи позже!</p>
                    </div>
                  ) : (
                    contests.map(c => {
                      const joined = participatedIds.includes(c.id);
                      return (
                        <div key={c.id} onClick={() => { setSelectedContest(c); setStep(joined ? ContestStep.SUCCESS : ContestStep.REFERRAL); }} className={`p-7 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.8rem] relative overflow-hidden active:scale-[0.97] transition-all shadow-sm border-2 ${joined ? 'border-green-500/30 bg-green-50/5' : 'border-transparent'}`}>
                          {joined && (
                            <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase flex items-center gap-1 shadow-lg z-10">
                              <CheckBadgeIcon className="w-3.5 h-3.5"/> В игре
                            </div>
                          )}
                          <h3 className="text-xl font-black mb-2 pr-10">{c.title}</h3>
                          <div className="flex items-center gap-2 mb-4">
                            <BanknotesIcon className="w-5 h-5 text-blue-600 opacity-50"/>
                            <span className="text-blue-600 font-black text-lg">{c.prizeRub?.toLocaleString()} ₽ <span className="text-xs opacity-30 font-bold ml-1">/ ${c.prizeUsd}</span></span>
                          </div>
                          <p className="text-xs opacity-50 line-clamp-2 mb-6 font-medium leading-relaxed">{c.description}</p>
                          <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-gray-800">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{joined ? 'Вы участвуете' : 'Начать участие'}</span>
                            <div className="w-8 h-8 rounded-full bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center">
                              <ArrowRightIcon className="w-4 h-4 text-blue-500"/>
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              )}
            </div>
          )}

          {step === ContestStep.REFERRAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-28 h-28 bg-blue-50 dark:bg-blue-900/10 rounded-[2.8rem] flex items-center justify-center shadow-inner relative">
                <LinkIcon className="w-14 h-14 text-blue-600"/>
                <div className="absolute -bottom-2 -right-2 bg-blue-600 text-white p-2 rounded-xl shadow-lg animate-bounce">
                  <CheckBadgeIcon className="w-5 h-5"/>
                </div>
              </div>
              <div className="space-y-4 px-4">
                <h1 className="text-3xl font-black tracking-tight">{selectedContest?.title}</h1>
                <p className="opacity-60 text-lg font-medium leading-relaxed">Для участия нужно быть зарегистрированным в системе Beef по нашей ссылке.</p>
              </div>
              <div className="w-full space-y-4">
                <a href={selectedContest?.referralLink} target="_blank" className="w-full p-6 bg-blue-600 text-white rounded-[2rem] font-black text-xl shadow-xl shadow-blue-600/30 flex items-center justify-center gap-3 active:scale-95 transition-all">
                  ПЕРЕЙТИ К РЕГИСТРАЦИИ <ArrowRightIcon className="w-6 h-6"/>
                </a>
                <button 
                  onClick={() => { 
                    setIsChecking(true); 
                    setTimeout(() => { 
                      setIsChecking(false); 
                      const nextAttempt = checkAttempts + 1;
                      setCheckAttempts(nextAttempt); 
                      if(nextAttempt >= 2) setStep(ContestStep.PAYOUT); 
                      else setError("Аккаунт не найден. Попробуй еще раз через 30-60 секунд."); 
                    }, 2000); 
                  }} 
                  disabled={isChecking} 
                  className="w-full py-5 border-2 border-blue-600 text-blue-600 rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 active:bg-blue-50 transition-all"
                >
                  {isChecking ? <ClockIcon className="w-6 h-6 animate-spin"/> : "Я зарегистрировался"}
                </button>
              </div>
              {error && <p className="text-red-500 font-bold animate-shake text-sm px-6 leading-tight">{error}</p>}
              <button onClick={() => setStep(ContestStep.LIST)} className="text-gray-400 font-bold uppercase text-[10px] tracking-widest pt-4">Назад к списку</button>
            </div>
          )}

          {step === ContestStep.PAYOUT && (
            <div className="p-8 h-full flex flex-col animate-fade-in">
              <div className="flex-1 space-y-12 pt-10">
                <div className="space-y-4 text-center">
                  <h1 className="text-5xl font-black tracking-tighter">ВЫПЛАТА</h1>
                  <p className="opacity-50 text-xl font-medium">Куда начислить выигрыш?</p>
                </div>
                <div className="flex bg-[var(--tg-theme-secondary-bg-color)] p-2 rounded-[2.2rem] border border-gray-100 dark:border-gray-800">
                  <button onClick={() => { setPayoutType('card'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.8rem] font-black text-xs transition-all ${payoutType === 'card' ? 'bg-white dark:bg-gray-800 shadow-xl text-blue-600' : 'opacity-40'}`}>БАНК. КАРТА</button>
                  <button onClick={() => { setPayoutType('trc20'); setPayoutValue(''); }} className={`flex-1 py-4 rounded-[1.8rem] font-black text-xs transition-all ${payoutType === 'trc20' ? 'bg-white dark:bg-gray-800 shadow-xl text-green-600' : 'opacity-40'}`}>USDT TRC20</button>
                </div>
                <div className="relative">
                  <div className="absolute left-6 top-1/2 -translate-y-1/2 opacity-20">
                    {payoutType === 'card' ? <CreditCardIcon className="w-8 h-8"/> : <CurrencyDollarIcon className="w-8 h-8"/>}
                  </div>
                  <input 
                    placeholder={payoutType === 'card' ? "0000 0000 0000 0000" : "Адрес кошелька..."}
                    value={payoutValue}
                    onChange={e => setPayoutValue(e.target.value)}
                    className="w-full py-7 pl-16 pr-8 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.5rem] text-2xl font-mono focus:border-blue-600 border-2 border-transparent transition-all outline-none shadow-sm"
                  />
                </div>
              </div>
              <button onClick={() => setStep(ContestStep.FINAL)} disabled={payoutValue.length < 8} className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-2xl shadow-2xl disabled:opacity-20 active:scale-95 transition-all mb-4">ПРОДОЛЖИТЬ</button>
            </div>
          )}

          {step === ContestStep.FINAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-32 h-32 bg-green-50 dark:bg-green-900/10 rounded-[3rem] flex items-center justify-center border-2 border-green-500/10 shadow-xl"><CheckBadgeIcon className="w-20 h-20 text-green-500"/></div>
              <div className="space-y-4 px-6">
                <h1 className="text-4xl font-black uppercase tracking-tight">ПОДТВЕРЖДЕНИЕ</h1>
                <p className="opacity-50 text-xl font-medium">Нажмите кнопку ниже, чтобы войти в список участников этого розыгрыша.</p>
              </div>
              <div className="w-full p-6 bg-gray-50 dark:bg-gray-900 rounded-[2.5rem] border border-gray-100 dark:border-gray-800 shadow-inner">
                 <p className="text-[10px] font-black uppercase opacity-30 mb-2 tracking-widest">Твои реквизиты</p>
                 <p className="font-mono text-lg font-black break-all">{payoutValue}</p>
              </div>
              <button onClick={() => { setIsFinalizing(true); setTimeout(() => { if(selectedContest) { const n = [...participatedIds, selectedContest.id]; setParticipatedIds(n); localStorage.setItem(PARTICIPATION_KEY, JSON.stringify(n)); } setIsFinalizing(false); setStep(ContestStep.SUCCESS); }, 1500); }} disabled={isFinalizing} className="w-full py-8 bg-blue-600 text-white rounded-[2.8rem] font-black text-2xl shadow-2xl flex items-center justify-center gap-4 active:scale-95 transition-all">
                {isFinalizing ? <ClockIcon className="w-8 h-8 animate-spin"/> : "ВСТУПИТЬ В РОЗЫГРЫШ"}
              </button>
            </div>
          )}

          {step === ContestStep.SUCCESS && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="relative">
                <div className="absolute inset-0 bg-green-500/20 blur-[5rem] rounded-full animate-pulse"></div>
                <div className="relative w-44 h-44 bg-gradient-to-tr from-green-600 to-emerald-400 rounded-full flex items-center justify-center text-white shadow-2xl border-4 border-white/20"><CheckBadgeIcon className="w-28 h-28"/></div>
              </div>
              <div className="space-y-4">
                <h1 className="text-4xl font-black uppercase tracking-tighter">ГОТОВО!</h1>
                <p className="opacity-60 text-xl px-10 font-medium">Вы в списке. Итоги будут опубликованы в канале. Желаем удачи!</p>
              </div>
              <button onClick={() => setStep(ContestStep.LIST)} className="text-blue-600 font-black uppercase tracking-widest text-sm flex items-center gap-2 py-5 px-10 bg-blue-50 dark:bg-blue-900/10 rounded-2xl active:scale-90 transition-all shadow-sm">
                <ChevronLeftIcon className="w-6 h-6"/> Назад к списку
              </button>
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(20px) scale(0.96); } to { opacity: 1; transform: translateY(0) scale(1); } }
        @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-6px); } 75% { transform: translateX(6px); } }
        .animate-fade-in { animation: fade-in 0.7s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .animate-shake { animation: shake 0.1s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TelegramUser, ContestStep, PayoutType, Contest } from './types';
import { 
  CheckBadgeIcon, 
  CreditCardIcon, 
  CurrencyDollarIcon, 
  ArrowRightIcon,
  LinkIcon,
  ClockIcon,
  TrashIcon,
  TrophyIcon,
  ChevronLeftIcon,
  ShieldCheckIcon,
  BanknotesIcon,
  SignalIcon
} from '@heroicons/react/24/outline';

// ========================================================
// 🔐 БАЗА ДАННЫХ ПОДКЛЮЧЕНА (Upstash Redis)
// ========================================================
const KV_REST_API_URL = 'https://golden-hound-18396.upstash.io'; 
const KV_REST_API_TOKEN = 'AUfcAAIncDJiMzQwNjMwYzUzOGM0NDI4YjQyNWQ3NjAzZDYwNDk2ZHAyMTgzOTY'; 
// ========================================================

const DB_KEY = 'beef_contests_v1';
const ADMIN_ID = 7946967720;
const PARTICIPATION_KEY = 'beef_user_participations_v3';

const App: React.FC = () => {
  const [view, setView] = useState<'user' | 'admin'>('user');
  const [step, setStep] = useState<ContestStep>(ContestStep.LIST);
  const [user, setUser] = useState<TelegramUser | null>(null);
  const [contests, setContests] = useState<Contest[]>([]);
  const [participatedIds, setParticipatedIds] = useState<string[]>([]);
  const [selectedContest, setSelectedContest] = useState<Contest | null>(null);
  const [usdRate, setUsdRate] = useState<number>(0.011); 
  const [isLoading, setIsLoading] = useState(true);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'none'>('none');

  // User States
  const [checkAttempts, setCheckAttempts] = useState(0);
  const [isChecking, setIsChecking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payoutType, setPayoutType] = useState<PayoutType>('card');
  const [payoutValue, setPayoutValue] = useState('');
  const [isFinalizing, setIsFinalizing] = useState(false);

  // Admin form
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPrizeRub, setNewPrizeRub] = useState<string>('');
  const [newLink, setNewLink] = useState('https://beef-way-one.com/c22082169');

  const fetchContests = async () => {
    setIsLoading(true);
    if (!KV_REST_API_URL || !KV_REST_API_TOKEN) {
      setDbStatus('none');
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
      setIsLoading(false);
      return;
    }

    try {
      const res = await fetch(`${KV_REST_API_URL}/get/${DB_KEY}`, {
        headers: { Authorization: `Bearer ${KV_REST_API_TOKEN}` }
      });
      const data = await res.json();
      if (data.result) {
        setContests(JSON.parse(data.result));
      }
      setDbStatus('connected');
    } catch (e) {
      console.error("DB Fetch Error:", e);
      setDbStatus('error');
      const local = localStorage.getItem(DB_KEY);
      setContests(local ? JSON.parse(local) : []);
    } finally {
      setIsLoading(false);
    }
  };

  const saveContestsGlobal = async (updated: Contest[]) => {
    localStorage.setItem(DB_KEY, JSON.stringify(updated));
    if (!KV_REST_API_URL || !KV_REST_API_TOKEN) return;

    try {
      await fetch(`${KV_REST_API_URL}/set/${DB_KEY}`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${KV_REST_API_TOKEN}` },
        body: JSON.stringify(updated)
      });
    } catch (e) {
      console.error("DB Save Error:", e);
    }
  };

  useEffect(() => {
    const tg = window.Telegram?.WebApp;
    if (tg) {
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user) {
        setUser(tg.initDataUnsafe.user);
      }
    }
    fetchContests();
    const p = localStorage.getItem(PARTICIPATION_KEY);
    if (p) setParticipatedIds(JSON.parse(p));

    fetch('https://open.er-api.com/v6/latest/RUB')
      .then(res => res.json())
      .then(data => { if (data.rates?.USD) setUsdRate(data.rates.USD); });
  }, []);

  const isAdmin = useMemo(() => user?.id === ADMIN_ID, [user]);

  const createContest = async () => {
    if (!newTitle || !newLink || !newPrizeRub) return;
    const rub = parseFloat(newPrizeRub);
    const contest: Contest = {
      id: Math.random().toString(36).substr(2, 9),
      title: newTitle,
      description: newDesc,
      prizeRub: rub,
      prizeUsd: Math.round(rub * usdRate),
      referralLink: newLink,
      createdAt: Date.now()
    };
    const updated = [contest, ...contests];
    setContests(updated);
    await saveContestsGlobal(updated);
    setNewTitle(''); setNewDesc(''); setNewPrizeRub('');
    setView('user');
    window.Telegram?.WebApp?.HapticFeedback.impactOccurred('medium');
  };

  const deleteContest = async (id: string) => {
    const updated = contests.filter(c => c.id !== id);
    setContests(updated);
    await saveContestsGlobal(updated);
  };

  return (
    <div className="h-screen bg-[var(--tg-theme-bg-color)] text-[var(--tg-theme-text-color)] overflow-hidden font-sans select-none">
      {isAdmin && dbStatus !== 'connected' && (
        <div className="bg-red-600 text-white text-[10px] py-1 px-4 text-center font-black animate-pulse uppercase sticky top-0 z-50 shadow-lg">
          ⚠️ ОШИБКА ПОДКЛЮЧЕНИЯ К БАЗЕ ДАННЫХ
        </div>
      )}

      {view === 'admin' ? (
        <div className="p-6 h-full overflow-y-auto pb-24 space-y-8 animate-fade-in bg-white dark:bg-black">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-black text-black dark:text-white leading-none">Админ-панель</h1>
              <div className="flex items-center gap-1.5 mt-2">
                <div className={`w-2 h-2 rounded-full ${dbStatus === 'connected' ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : 'bg-red-500'}`}></div>
                <span className={`text-[10px] font-bold uppercase tracking-wider ${dbStatus === 'connected' ? 'text-green-600' : 'text-red-600'}`}>
                  {dbStatus === 'connected' ? 'База данных онлайн' : 'Нет связи с базой'}
                </span>
              </div>
            </div>
            <button onClick={() => setView('user')} className="text-blue-600 font-black p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl active:scale-95 transition-all text-xs uppercase tracking-widest">Выход</button>
          </div>

          <div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-[2.5rem] space-y-4 border border-gray-200 dark:border-gray-800 shadow-xl">
            <div className="space-y-1">
               <label className="text-[10px] font-black uppercase opacity-40 px-2">Заголовок</label>
               <input 
                placeholder="Зимний розыгрыш 10к" 
                value={newTitle} 
                onChange={e => setNewTitle(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-black dark:text-white font-bold text-lg"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black uppercase opacity-40 px-2">Описание конкурса</label>
              <textarea 
                placeholder="Опиши условия коротко и ясно..." 
                value={newDesc} 
                onChange={e => setNewDesc(e.target.value)}
                className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 h-24 text-black dark:text-white"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase opacity-40 px-2">Сумма RUB</label>
                <input 
                  type="number"
                  placeholder="5000" 
                  value={newPrizeRub} 
                  onChange={e => setNewPrizeRub(e.target.value)}
                  className="w-full p-4 bg-white dark:bg-gray-800 rounded-2xl border border-gray-300 dark:border-gray-700 text-blue-600 font-black text-xl"
                />
              </div>
              <div className="space-y-1 opacity-50">
                <label className="text-[10px] font-black uppercase px-2">Эквивалент USD</label>
                <div className="w-full p-4 bg-gray-100 dark:bg-gray-950 rounded-2xl font-black text-xl">
                  ${newPrizeRub ? Math.round(parseFloat(newPrizeRub) * usdRate) : 0}
                </div>
              </div>
            </div>
            <button 
              onClick={createContest}
              disabled={!newTitle || !newPrizeRub}
              className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-lg shadow-xl shadow-blue-600/30 active:scale-95 transition-all disabled:opacity-20"
            >
              ОПУБЛИКОВАТЬ КОНКУРС
            </button>
          </div>

          <div className="space-y-4 pb-10">
            <h2 className="font-black text-[10px] uppercase tracking-widest opacity-30 px-2">Текущие розыгрыши</h2>
            {contests.length === 0 && <div className="text-center py-10 opacity-20 italic">Пока ничего не создано</div>}
            {contests.map(c => (
              <div key={c.id} className="p-5 bg-gray-50 dark:bg-gray-900 rounded-[2rem] flex justify-between items-center border border-gray-100 dark:border-gray-800 shadow-sm">
                <div className="overflow-hidden mr-4">
                  <p className="font-black text-black dark:text-white truncate text-base">{c.title}</p>
                  <p className="text-xs text-blue-600 font-bold">{c.prizeRub.toLocaleString()} ₽</p>
                </div>
                <button onClick={() => deleteContest(c.id)} className="p-3 text-red-500 bg-red-50 dark:bg-red-900/20 rounded-2xl active:scale-90 transition-all">
                  <TrashIcon className="w-6 h-6"/>
                </button>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="h-full">
          {step === ContestStep.LIST && (
            <div className="p-6 space-y-8 animate-fade-in overflow-y-auto h-full pb-24">
              <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-blue-600 rounded-[1.2rem] flex items-center justify-center text-white shadow-xl shadow-blue-600/20"><TrophyIcon className="w-7 h-7"/></div>
                  <div>
                    <h1 className="text-xl font-black leading-none">Beef Contest</h1>
                    <p className="text-[10px] uppercase font-black text-blue-500 tracking-wider mt-1">Твой путь к победе</p>
                  </div>
                </div>
                {isAdmin && (
                  <button onClick={() => setView('admin')} className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-2xl relative">
                    <ShieldCheckIcon className="w-7 h-7 text-blue-600"/>
                    <div className={`absolute -top-1 -right-1 w-3 h-3 rounded-full border-2 border-white dark:border-black ${dbStatus === 'connected' ? 'bg-green-500' : 'bg-red-500'}`}></div>
                  </button>
                )}
              </div>

              {isLoading ? (
                <div className="flex flex-col items-center justify-center py-32 opacity-20 gap-4">
                  <ClockIcon className="w-12 h-12 animate-spin"/>
                  <p className="font-black text-[10px] uppercase tracking-[0.4em]">Обновляем данные...</p>
                </div>
              ) : (
                <div className="space-y-5">
                  {contests.length === 0 ? (
                    <div className="text-center py-20 px-10">
                      <div className="w-20 h-20 bg-gray-100 dark:bg-gray-900 rounded-full flex items-center justify-center mx-auto mb-6 opacity-30">
                        <SignalIcon className="w-10 h-10"/>
                      </div>
                      <p className="opacity-30 italic font-medium">Новых розыгрышей пока нет. Заходи позже!</p>
                    </div>
                  ) : (
                    contests.map(c => {
                      const joined = participatedIds.includes(c.id);
                      return (
                        <div key={c.id} onClick={() => { setSelectedContest(c); setStep(joined ? ContestStep.SUCCESS : ContestStep.REFERRAL); }} className={`p-7 bg-[var(--tg-theme-secondary-bg-color)] rounded-[2.8rem] relative overflow-hidden active:scale-[0.97] transition-all shadow-sm border-2 ${joined ? 'border-green-500/30' : 'border-transparent'}`}>
                          {joined && (
                            <div className="absolute top-0 right-0 bg-green-500 text-white px-4 py-1.5 rounded-bl-2xl text-[10px] font-black uppercase flex items-center gap-1 shadow-lg z-10">
                              <CheckBadgeIcon className="w-3.5 h-3.5"/> Участвую
                            </div>
                          )}
                          <h3 className="text-xl font-black mb-2 pr-10">{c.title}</h3>
                          <div className="flex items-center gap-2 mb-4">
                            <BanknotesIcon className="w-5 h-5 text-blue-600 opacity-50"/>
                            <span className="text-blue-600 font-black text-lg">{c.prizeRub?.toLocaleString()} ₽ <span className="text-xs opacity-30 font-bold ml-1">/ ${c.prizeUsd}</span></span>
                          </div>
                          <p className="text-xs opacity-50 line-clamp-2 mb-6 font-medium leading-relaxed">{c.description}</p>
                          <div className="flex items-center justify-between pt-4 border-t border-gray-100 dark:border-gray-800">
                            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{joined ? 'Вы в списке' : 'Записаться'}</span>
                            <div className="w-8 h-8 rounded-full bg-blue-50 dark:bg-blue-900/20 flex items-center justify-center">
                              <ArrowRightIcon className="w-4 h-4 text-blue-500"/>
                            </div>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>
              )}
            </div>
          )}

          {step === ContestStep.REFERRAL && (
            <div className="p-6 h-full flex flex-col justify-center items-center text-center space-y-12 animate-fade-in">
              <div className="w-28 h-28 bg-blue-50 dark:bg-blue-900/10 rounded-[2.8rem] flex items-center justify-center shadow-inner relative">
                <LinkIcon className="w-14 h-14 text-blue-600"/>
