                  </div>
                  <button onClick={() => setAdminSelectedContest(null)} className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full active:scale-90 transition-all"><ChevronLeftIcon className="w-6 h-6 rotate-90"/></button>
