            <div className="fixed inset-0 z-[110] bg-white dark:bg-[#0c0d10] flex flex-col p-8 animate-slide-up">
              <button onClick={() => setStep(ContestStep.LIST)} className="absolute top-8 left-8 p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl active:scale-90 transition-all">
                <ChevronLeftIcon className="w-6 h-6"/>
              </button>

              <div className="flex-1 flex flex-col justify-center items-center text-center space-y-10">
                {step === ContestStep.REFERRAL && (
                  <>
                    <div className="relative w-28 h-28 bg-blue-600/5 rounded-full flex items-center justify-center">
                      <LinkIcon className="w-14 h-14 text-blue-600"/>
                      <div className="absolute bottom-2 right-2 bg-blue-600 p-1.5 rounded-xl border-4 border-white dark:border-[#0c0d10]"><CheckBadgeIcon className="w-4 h-4 text-white"/></div>
