                    <div className="w-full max-w-[300px] flex flex-col gap-3">
                      <a href={selectedContest?.referralLink} target="_blank" className="w-full py-5 bg-blue-600 text-white rounded-[1.8rem] font-bold text-lg active:scale-95 transition-all">Зарегистрироваться</a>
                      <button 
                        onClick={() => {
                          setIsChecking(true); 
                          setTimeout(() => {
                            setIsChecking(false);
