                    </div>
                    <button onClick={() => { saveProfile({...profile, payoutValue, payoutType: 'card'}); setStep(ContestStep.FINAL); }} disabled={payoutValue.length < 16} className="w-full py-5 bg-blue-600 text-white rounded-3xl font-bold text-lg disabled:opacity-20">Продолжить</button>
                  </div>
                )}

                {step === ContestStep.FINAL && (
                  <>
                    <div className="w-24 h-24 bg-green-500/5 rounded-3xl flex items-center justify-center border-2 border-green-500/10"><FlagIcon className="w-10 h-10 text-green-500"/></div>
                    <h1 className="text-3xl font-black uppercase">Подтверждение</h1>
                    <div className="w-full p-6 bg-slate-50 dark:bg-slate-900 border rounded-3xl">
